// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../../jibo');
import Playback = JiboImport.animDB.Playback;
import AnimQuery = JiboImport.animDB.AnimQuery;
// ------------------------------------------------

import * as uuid from 'uuid';
import * as path from 'path';
import { CacheUtils, PromiseQueue } from 'jibo-cai-utils';
import { StateMachine } from 'jibo-state-machine';

import { EmbodiedDialog, EmbodiedOptions } from '../EmbodiedDialog';
import { Dataflow, SpeakOptions, DispatchType, AutoRuleConfig, Session, RequestStatus } from './common/Types';
import { InputProcessor } from './processing/InputProcessor';
import { NLParser } from './processing/parsers/NLParser';
import { AutoRuleManager } from './processing/auto_rules/AutoRuleManager';
import { TimelineManager } from "./timelines/TimelineManager";
import { Utils } from '../utils/Utils';
import { Validation } from './utils/Validation';
import { CreateTimelineState, BuildDispatchableState, DispatchState, CompleteState } from './states';

import * as logs from '../log';
const log = logs.speechLog;

const DEFAULT_FRAME_BUFFER_MS = 0;

/**
 * @intdocs
 */
export class EmbodiedSpeech {

  /*
   * @private
   */
  public ed: EmbodiedDialog;
  /*
   * @private
   */
  public jibo: typeof JiboImport;
  /*
   * @private
   */
  public inputProcessor: InputProcessor;
  /*
   * @private
   */
  public nlParser: NLParser;
  /*
   * @private
   */
  public autoRuleManager: AutoRuleManager;
  /*
   * @private
   */
  public timelineManager: TimelineManager;
  /*
   * @private
   */
  public log = log;
  /*
   * @private
   */
  public ownerInformation = 'EmbodiedSpeech';
  /*
   * @private
   */
  public dofsToCenter: any;
  /*
   * @private
   */
  public playingKeys: Playback[] = [];
  /*
   * @private
   */
  public animationDispatchPr: Promise<void> = Promise.resolve();
  /*
   * @private
   */
  public active: Session = null;

  private sm = new StateMachine();
  private createTimelineState = new CreateTimelineState(this.sm, this, 'Create Timeline');
  private buildDispatchableState = new BuildDispatchableState(this.sm, this, 'Build Dispatchable');
  private dispatchState = new DispatchState(this.sm, this, 'Dispatch');
  private completeState = new CompleteState(this.sm, this, 'Complete');

  private queue = new PromiseQueue();
  private unresolved = new Set<Session>();
  private isStopping: boolean = false;

  private _speakOptions: SpeakOptions;
  private _autoRuleConfig: AutoRuleConfig;


  /**
   * Constructs (but does not init) Embodied Speech instance
   *
   * @param {EmbodiedDialog} _ed
   */
  constructor(_ed: EmbodiedDialog) {
    this.ed = _ed;

    // Set up states
    this.sm.setInitial(this.createTimelineState);
    this.createTimelineState.addDoneTransition(this.buildDispatchableState);
    this.buildDispatchableState.addDoneTransition(this.dispatchState);
    this.dispatchState.addDoneTransition(this.completeState);
  }

  /**
   * Initializes Embodied Speech instance
   *
   * @param {any} jibo instance
   * @param {boolean} [debug=false] Toggle debug mode
   * @param {EmbodiedOptions} [options] Embodied Speech will use to initialize with
   * @param {AutoRuleConfig} [autoRuleConfig] Embodied Speech will use to initialize with
   * @returns {Promise<void>} Resolved when completed initialization
   */
  async init(jibo: any, debug=false, options?: EmbodiedOptions, autoRuleConfig?: AutoRuleConfig): Promise<void> {

    if (jibo) {
      this.jibo = jibo;
    } else {
      throw new Error('Cannot instantiate without Jibo instances!');
    }

    // Wait for for Jibo's face to be initialized before trying to load animations into cache
    jibo.timer.once('update', () => {
      log.debug('Caching common Embodied Speech AutoRule animations.');
      const blinksQuery: AnimQuery = {
        categories: ['blinks'],
        includeSomeMeta: ['single', 'double'],
        excludeMeta: ['sfx-only', 'ssa-only']
      };
      const beatQuery: AnimQuery = {
        categories: ['poses'],
        includeMeta: ['initiation'],
        excludeMeta: ['sfx-only', 'ssa-only']
      };
      const commaQuery: AnimQuery = {
        categories: ['comma'],
        excludeMeta: ['sfx-only', 'ssa-only']
      };
      const questionQuery: AnimQuery = {
        categories: ['question'],
        excludeMeta: ['eye-only', 'sfx-only', 'ssa-only']
      };

      // Cache common AutoRule animations into CacheUtils
      [blinksQuery, beatQuery, commaQuery, questionQuery].forEach(async query => {
        try {
          await Utils.loadAnimationIntoCache(jibo, query, CacheUtils.GlobalCacheName);
        } catch (err) {
          log.warn(`Unable to load animations from query  ${JSON.stringify(query)}  into cache  ${CacheUtils.GlobalCacheName}`);
        }
      });
    });

    const dofsAll = this.jibo.expression.dofs.ALL;
    this.dofsToCenter = dofsAll.minus(this.jibo.expression.dofs.LED)
      .minus(this.jibo.expression.dofs.BODY).minus(this.jibo.expression.dofs.EYE_TRANSLATE);

    // Default speak options
    const defaultSpeakOptions = {
      disableAutoRules: false,
      dispatchComplete: DispatchType.ALL,
      enableLayerMerging: true,
      frameBuffer: Utils.millisecToSec(DEFAULT_FRAME_BUFFER_MS),
      followedByListen: false,
      debugMode: debug
    };
    this._speakOptions = Validation.validateSpeakOptions(defaultSpeakOptions, options);

    // Default autoRule configuration
    const allowAutoRule = !this._speakOptions.disableAutoRules;
    const defaultAutoRuleConfig = {
      interSentenceTiming: false,
      intraSentenceTiming: false,
      hotWords: allowAutoRule,
      punctuation: allowAutoRule,
      structure: false,
      voice: allowAutoRule,
      beat: allowAutoRule,
      themeRheme: false
    };
    this._autoRuleConfig = Validation.validateAutoRuleConfig(defaultAutoRuleConfig, autoRuleConfig);

    this.inputProcessor = new InputProcessor(this.jibo);
    this.nlParser = new NLParser(this.jibo);
    this.autoRuleManager = new AutoRuleManager(this.jibo);

    // Initialize resourceRoot
    let resourceRoot: string;
    if (options && options.resourceRoot) {
      resourceRoot = options.resourceRoot;
    }
    this.setResourceRoots(resourceRoot);
  }

  /**
   * Speaks text using coordinated gestures/behaviors that a mix of
   * auto-generated and user-defined behaviors.
   *
   * @param {String} textToSpeak The text that Jibo should speak.
   * @param {SpeakOptions} speakOptions
   * @param {AutoRuleConfig} autoRuleConfig
   * @return {Promise<RequestStatus>} A promise that is resolved when Jibo is done speaking (naturally or stopped).
   */
  async speak(textToSpeak: string, speakOptions?: SpeakOptions, autoRuleConfig?: AutoRuleConfig): Promise<RequestStatus> {
    log.info("Speak request received");
    this.jibo.performance.log('EmbodiedSpeechStartSkill', 'When ES is called');

    if (this.active) {
      this.stop();
    }

    return new Promise<RequestStatus>(async (resolve, reject) => {
        const session: Session = {
          resolve,
          reject,
          id: uuid.v4(),
          wasStopped: false
        };
        this.unresolved.add(session);
        this.queue.add(async () => {
          this.active = session;
          this.unresolved.delete(session);
          try {
            await this._speak(textToSpeak, session, speakOptions, autoRuleConfig);
          } catch (error) {
            reject(error);
          } finally {
            this.active = null;
            log.info("Ready for next speak request");
            if (session.wasStopped) {
              this.isStopping = false;
              resolve(RequestStatus.STOPPED);
            } else {
              resolve(RequestStatus.SUCCEEDED);
            }
          }
        });
      });
  }

  async _speak(textToSpeak: string, session: Session, speakOptions?: SpeakOptions, autoRuleConfig?: AutoRuleConfig): Promise<void> {
    log.info("Processing speak request");

    const validatedOptions = Validation.validateSpeakOptions(this._speakOptions, speakOptions);
    log.debug("Validated Speak Options: ", validatedOptions);
    const validatedConfig = Validation.validateAutoRuleConfig(this._autoRuleConfig, autoRuleConfig);
    log.debug("Validated AutoRule Config: ", validatedConfig);

    const data: Dataflow = {
      session: session.id,
      textToSpeak: textToSpeak,
      speakOptions: validatedOptions,
      autoRuleConfig: validatedConfig,
      centeringEnabled: false
    };

    log.info("Starting new speak session: ", session.id);
    return this.sm.start(data);
  }

  /**
   * Stop all current and future animations and TTS
   *
   * @return {Promise<void>}
   */
  async stop(): Promise<void> {
    log.info("Stop request received");
    if (this.active && !this.isStopping) {
      this.isStopping = true;
      this.active.wasStopped = true;
      this._stop();
    }
    this.queue.clear();
    const temp = this.unresolved;
    this.unresolved = new Set<Session>();
    temp.forEach(session => {
      log.info("Stopping queued session: ", session.id);
      session.resolve(RequestStatus.STOPPED);
    });
    return this.queue.waitUntilEmpty()
      .then(() => null);
  }

  async _stop(): Promise<void> {
    if (this.active) {
      log.info("Processing stop request on active session: ", this.active.id);
      return this.sm.stop();
    }
  }

  /**
   * Update all resource roots (Base, Anim and Audio)
   *
   * @param {String} root new resourceRoot path
   */
  setResourceRoots(root: string) {
    const resourceRoot = root;
    let animResourceRoot: string;
    let audioResourceRoot: string;
    if (resourceRoot) {
      log.debug(`Setting new resource roots based off of:  ${root}`);
      animResourceRoot = path.join(resourceRoot, 'animations');
      audioResourceRoot = path.join(resourceRoot, 'audio');
    } else {
      log.debug(`Clearing resource roots`);
    }
    this.timelineManager = new TimelineManager(this.jibo, resourceRoot, animResourceRoot, audioResourceRoot);
  }

  /**
   * Get current activity status of Embodied Speech
   *
   * @return {boolean} Whether or not Embodied Speech is currently processing a Speak request
   */
  isActive(): boolean {
    return !!this.active;
  }

  /**
   * Retrieve a promise linked to the state Embodied Speech animation dispatch
   *
   * @return {Promise<void>} Promise providing the current state of Embodied Speech animation dispatch
   */
  waitForAnimDispatch(): Promise<void> {
      return this.animationDispatchPr;
  }

}
