import JiboImport = require('../../../../../jibo');  // Just for typings, not available at runtime

import * as _ from 'lodash/lodash.min';
import Node from 'jibo-node-xml';
import { AttType } from 'jibo-node-xml';
import { AutoRule } from './AutoRule';
import { NLPNodeType, AssetNodeType, WordType } from '../../common/Types';
import { AssetNode } from "../AssetNode";
import { SentenceNode } from '../parsers/NLParser';
import { AutoRuleUtils } from './AutoRuleUtils';
import { AutoRuleNames } from './AutoRuleManager';


/**
 * Keys utilized by the list rule to keep track of the subrule information
 */
const AR_LIST_SUB_RULE_KEY = 'ar-list-subrule';
const AR_LIST_SUB_RULE_PART_KEY = 'ar-list-subrule-part';


/**
 * Keys file names utilized by the list rule
 */
export const LIST_RULE_TYPES = {
    SUB_RULE_1: 'list-rule-sr1',
    SUB_RULE_2: 'list-rule-sr2'
};


export class ListRule extends AutoRule {

    private Orientation = this.jibo.animDB.Orientation;
    private lastOrientation;

    /**
     * @param {jibo} jibo
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(private jibo: typeof JiboImport, priority = 1, probability = 1) {
        super(AutoRuleNames.List, priority, probability);
    }

    _createNode(children: Node[]) {
        const segmentSubRule = children[0].getAttribute(AR_LIST_SUB_RULE_KEY) as string;
        const segmentSubRulePart = children[0].getAttribute(AR_LIST_SUB_RULE_PART_KEY) as string;
        this.lastOrientation = (Math.random() > 0.5) ? this.Orientation.LEFT : this.Orientation.RIGHT;
        let atts = new Map<string, AttType>();
        if (segmentSubRulePart) {
            atts.set('filter', segmentSubRulePart);
        }
        let n = new AssetNode(AssetNodeType.ANIM, atts);
        n.setAttribute('cat', segmentSubRule);
        n.setAttribute('orientation', this.lastOrientation);
        n.setAttribute('rule', AutoRuleNames.List);
        if (segmentSubRule === LIST_RULE_TYPES.SUB_RULE_2 && segmentSubRulePart === 'a') {
            n.setAttribute('endNeutral', 'false');
        } else {
            n.setAttribute('endNeutral', `true`);
        }
        return n;
    }

    /**
     * Applies this rule and produces a list of lists of consecutive word nodes
     * which should have this rule applied to them
     *
     * @param {Node} nlpTreeRoot
     * @param {Node[]} [otherRoots]
     * @return {Node[][]}
     * @private
     */
    _applyInternal(nlpTreeRoot: Node, otherRoots?: Node[]): Node[][] {
        let sequences = [];

        nlpTreeRoot.forEachChildType(NLPNodeType.SENTENCE, (sentence: SentenceNode) => {
            const wordSegments = AutoRuleUtils.getWordsFromSentenceSegmentedBy([',', 'and'], sentence);
            if (wordSegments.length >= 3) {  // We need at least 3 subsections to possibly be a list
                let possibleListSegments = [];
                let segmentCount = 0;
                wordSegments.forEach( segment => {
                    if (segmentCount === 0) {  // If this is the first of a new possible list
                        let verbIdx = -1;
                        for (let idx = 0; idx < segment.length; idx++) {
                            if (segment[idx].wordType === WordType.VERB) {
                                verbIdx = idx;
                                break;
                            }
                        }
                        let slicedSegment: Node[];
                        if (verbIdx !== -1) {  // If there's a verb in this section, only take the words after the verb until the comma (or and)
                            slicedSegment = segment.slice(verbIdx + 1);
                        } else {  // Otherwise, only take up to the last 3 words preceding the comma (or and)
                            slicedSegment = segment.slice(-3);
                        }
                        if (slicedSegment.length > 0) {
                            possibleListSegments.push(slicedSegment);
                            segmentCount++;
                        }
                    } else if (segment.length <= 3) {  // If we've found another valid list subsection
                        segmentCount++;
                        possibleListSegments.push(segment);
                    } else {  // If we've encountered an invalid list subsection
                        if (segmentCount < 3) {  // If our in progress list doesn't already have 3 subsections -- reset
                            possibleListSegments = [];
                            segmentCount = 0;
                        } else {  // Otherwise, if our in progress list already has 3 subsections -- store it as a list and reset our count
                            sequences.push(...this._addListSubRuleInfo(possibleListSegments));
                            possibleListSegments = [];
                            segmentCount = 0;
                        }
                    }
                });
                // If the segments end in a valid, in progress list and it already has 3 subsections -- store it as a list
                if (possibleListSegments && possibleListSegments.length >= 3) {
                    sequences.push(...this._addListSubRuleInfo(possibleListSegments));
                }
            }
        });

        return sequences;
    }

    /**
     * Adds some metadata to nodes that are apart of the list (for later list rule use)
     *
     * @param {Node[][]} listSegments
     * @private
     */
    _addListSubRuleInfo(listSegments: Node[][]) {
        const choice = _.sample(_.values(LIST_RULE_TYPES)) as string;

        let mergedSegments: Node[][] = [];
        if (choice === LIST_RULE_TYPES.SUB_RULE_1) {
            let mergingList = [];
            for (let idx = 0; idx < listSegments.length - 1; idx++) {
                if ((idx === 0) && (listSegments[idx].length > 0)) {
                    listSegments[idx][0].setAttribute(AR_LIST_SUB_RULE_KEY, choice);
                }
                mergingList.push(...listSegments[idx]);
            }
            mergedSegments.push(mergingList);
        } else {
            let mergingList = [];
            for (let idx = 0; idx < listSegments.length; idx++) {
                if (idx === 0) {
                    if (listSegments[idx].length > 0) {
                        listSegments[idx][0].setAttribute(AR_LIST_SUB_RULE_KEY, choice);
                        listSegments[idx][0].setAttribute(AR_LIST_SUB_RULE_PART_KEY, 'a');
                    }
                    mergingList.push(...listSegments[idx]);
                } else if (idx === listSegments.length - 1) {
                    mergedSegments.push(mergingList);
                    mergingList = [];
                    if (listSegments[idx].length > 0) {
                        listSegments[idx][0].setAttribute(AR_LIST_SUB_RULE_KEY, choice);
                        listSegments[idx][0].setAttribute(AR_LIST_SUB_RULE_PART_KEY, 'b');
                    }
                    mergingList.push(...listSegments[idx]);
                    mergedSegments.push(mergingList);
                } else {
                    mergingList.push(...listSegments[idx]);
                }
            }
        }

        return mergedSegments;
    }

}
