import JiboImport = require('../../../../../jibo');  // Just for typings, not available at runtime

import Node from 'jibo-node-xml';
import { AttType } from 'jibo-node-xml';
import { AutoRule } from './AutoRule';
import { NLPNodeType, AssetNodeType } from '../../common/Types';
import { AssetNode } from "../AssetNode";
import { WordNode } from '../parsers/NLParser';
import { AutoRuleUtils } from './AutoRuleUtils';
import { AutoRuleNames } from './AutoRuleManager';


export class InitiateRule extends AutoRule {

    private Orientation = this.jibo.animDB.Orientation;
    private lastOrientation = (Math.random() > 0.5) ? this.Orientation.LEFT : this.Orientation.RIGHT;

    /**
     * @param {jibo} jibo
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(private jibo: typeof JiboImport, priority = 1, probability = 1) {
        super(AutoRuleNames.Initiate, priority, probability);
    }

    _createNode(children: Node[]) {
        this.lastOrientation = this.lastOrientation === this.Orientation.LEFT ? this.Orientation.RIGHT : this.Orientation.LEFT;
        let atts = new Map<string, AttType>();
        atts.set('layers', 'body');
        atts.set('filter', 'initiation');
        atts.set('cat', 'poses');
        let n = new AssetNode(AssetNodeType.ANIM, atts);
        n.setAttribute('rule', AutoRuleNames.Initiate);
        n.setAttribute('orientation', this.lastOrientation);
        return n;
    }

    /**
     * Applies this rule and produces a list of lists of consecutive word nodes
     * which should have this rule applied to them
     * @param {Node} nlpTreeRoot
     * @param {Node[]} [otherRoots]
     * @return {Node[][]}
     * @private
     */
    _applyInternal(nlpTreeRoot: Node, otherRoots?: Node[]): Node[][] {
        let sequences = [];

        nlpTreeRoot.forEachChildType(NLPNodeType.SENTENCE, sentence => {
            const wordNodes = sentence.gatherDescendantsType(NLPNodeType.WORD) as WordNode[];
            const noExpansions = AutoRuleUtils.removeExpandedContractionWords(wordNodes);
            let firstWords = [];
            for (let idx = 0; idx < Math.min(3, noExpansions.length); idx++) {
                firstWords.push(noExpansions[idx]);
            }
            if (firstWords.length > 0) {
                sequences.push(firstWords);
            }
        });

        return sequences;
    }

}
