/*
 * @fileOverview
 * An auto rule which applies certain timing changes to inter-sentence modifiers
 * (e.g. periods, question marks, exclamation marks).
 */

import Node from 'jibo-node-xml';
import { TimelineAutoRule } from './TimelineAutoRule';
import { TagTreeNode } from '../../TagTreeNode';
import { TimelineModifyingRuleNames } from '../AutoRuleManager';
import { AR_SUBRULE } from '../AutoRuleUtils';
import {
  TimelineModUtils,
  TimelineAutoRuleInsertionInfo,
  TimelineAutoRuleType,
  TimelineAutoRuleMatchInfo
} from './TimelineModUtils';

/**
 * Minimum duration for a period pause inserted by AutoRules
 */
export const AR_MIN_PERIOD_PAU = 0.1;


/**
 * Maximum duration for a period pause inserted by AutoRules
 */
export const AR_MAX_PERIOD_PAU = 0.3;


/**
 * Duration for a question pause inserted by AutoRules
 */
export const AR_QUESTION_PAU = 0.3;


/**
 * Duration for a exclamation pause inserted by AutoRules
 */
export const AR_EXCLAMATION_PAU = 0.3;


/**
 * Duration for an "ellipsis" pause inserted by AutoRules
 */
export const AR_ELLIPSIS_PAU = 0.75;


export class InterSentenceTimingRule extends TimelineAutoRule {


    /**
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(priority = 1, probability = 1) {
        super(TimelineModifyingRuleNames.InterSentenceTiming, TimelineAutoRuleType.TIMEFUL, priority, probability);
    }

    /**
     * Create SSML/break node and gather insertion information
     *
     * @param {TimelineAutoRuleMatchInfo} matchInfo
     * @return {Array<Node, TimelineAutoRuleInsertionInfo>}
     * @private
     */
    _createTimelineModifyingData(matchInfo: TimelineAutoRuleMatchInfo): [Node, TimelineAutoRuleInsertionInfo] {

        let breakSize = 0;

        switch (matchInfo.subRule) {
            case AR_SUBRULE.PERIOD:
                breakSize = (matchInfo.sibling.getNumberAtt('wordCount') <= 3) ? AR_MIN_PERIOD_PAU : AR_MAX_PERIOD_PAU;
                break;
            case AR_SUBRULE.QUESTION:
                breakSize = AR_QUESTION_PAU;
                break;
            case AR_SUBRULE.EXCLAMATION:
                breakSize = AR_EXCLAMATION_PAU;
                break;
            case AR_SUBRULE.ELLIPSIS:
                breakSize = AR_ELLIPSIS_PAU;
                break;
        }
        if (breakSize > 0) {
            const n = TimelineModUtils.breakNodeBuilder(breakSize);
            return TimelineModUtils.getInsertionInfo(n, matchInfo.sibling, 1);
        }

        return;
    }

    /**
     * Gathers all nodes that match any of the punctuation related to the InterSentence timing rule (i.e. ., ?, !)
     *
     * @param {TagTreeNode} xmlTree
     * @param {boolean} doPunctuation If only the timing aspects related to the ellipsis autoRule are desired
     * @return {Array<Array<Node, string>>} Nodes that match and which subrule was matched
     * @private
     */
    _applyInternal(xmlTree: TagTreeNode, doPunctuation: boolean): TimelineAutoRuleMatchInfo[] {
        let matchesInfo: TimelineAutoRuleMatchInfo[] = [];
        let endedTextInPunctLoc = null;
        let wordCount = 0;
        xmlTree.forEachDescendant( node => {
            switch (node.value) {
                case AR_SUBRULE.PERIOD:
                case AR_SUBRULE.QUESTION:
                case AR_SUBRULE.EXCLAMATION:
                    endedTextInPunctLoc = matchesInfo.length;
                    node.setAttribute('wordCount', wordCount);
                    matchesInfo.push({
                        sibling: node,
                        subRule: node.value
                    });
                    wordCount = 0;
                    break;
                case AR_SUBRULE.ELLIPSIS:
                    if (!doPunctuation) {
                        endedTextInPunctLoc = matchesInfo.length;
                        matchesInfo.push({
                            sibling: node,
                            subRule: AR_SUBRULE.ELLIPSIS
                        });
                    }
                    break;
                default:
                    endedTextInPunctLoc = null;
                    if (/\w+/.test(node.value)) {  // If this is a word
                        wordCount++;
                    }
            }
        });
        if (endedTextInPunctLoc !== null) {
            matchesInfo.splice(endedTextInPunctLoc, 1);
        }

        return matchesInfo;
    }

}
