// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../../jibo');
type AnimConfig = JiboImport.animDB.AnimConfig;
type PlaybackOptions = JiboImport.animDB.PlaybackOptions;
// ------------------------------------------------

import { PromiseQueue, PromiseProvider, CacheUtils } from 'jibo-cai-utils';
import { State, StateMachine } from 'jibo-state-machine';
import { VisualPerceptionState, ListeningState, AmbientListenMode, ActiveListenMode, RequestStatus, ActiveModeOptions } from './Types';
import { IncomingEvents, OutgoingEvents, InternalEvents } from './Events';
import { Utils } from './Utils';
import { timeout, ExtPromise, Utils as EmbodiedUtils } from '../utils/Utils';
import { Led, AnimSelector, EyeTransitionDirection, EyeTransitionStyle } from './Assets';
import { EmbodiedDialog } from '../EmbodiedDialog';


import * as logs from '../log';
const log = logs.listenLog;

const HJ_BLINK_INTERVAL = 25 * 1000; // 25 s in ms
// const HJ_SOUND_INTERVAL = 3 * 60 * 1000; // 3 minutes
const USE_CENTER_ROBOT = false;
const TIMEOUT = 3000;
const ANIM_CLEAR_TIMEOUT = 'ANIM_CLEAR_TIMEOUT';

/**
 * @intdocs
 */
export class EmbodiedListen extends StateMachine {

  static NONHJ_OWNER_INFORMATION = 'EmbodiedListen';
  static HJ_OWNER_INFORMATION = 'BargeIn';

  public _queue = new PromiseQueue();
  public _lastAnimInstance: any;

  // All the different states
  public _idle = new State(this, 'Idle');
  public _reset = new State(this, 'Reset');
  public _hjExpression = new State(this, 'HJ Expression');
  public _nonHjExpression = new State(this, 'NonHJ Expression');
  public _offExpression = new State(this, 'Off Expression');
  public _engage = new State(this, 'Engage');
  public _listening = new State(this, 'Listen');
  public _thinking = new State(this, 'Off Expression + Thinking');
  public _waitForAnimFinish = new State(this, 'Wait for anim finish');
  public _active = new State(this, 'Active Mode');

  public listenState = ListeningState.NOT_LISTENING;
  public perceptualState: VisualPerceptionState;

  public debugPerceptualEye = false;

  public eventsIn = new IncomingEvents();
  public eventsOut = new OutgoingEvents();
  private eventsInternal = new InternalEvents();

  private _jibo: typeof JiboImport;
  private _debug: boolean;

  private _disableOnce = false;
  private _lastHeadBob = -1;
  private _nextHeadBob = 0;

  private _ambientMode = AmbientListenMode.NORMAL;
  private _activeMode: ActiveListenMode = null;
  private _pendingActiveMode: ActiveListenMode;
  private _pendingActiveModeExtPr: ExtPromise<RequestStatus>;

  private _lastHJBlinkTime = -1;
  // private _lastHJSoundTime = -1;
  private DOFS_ALL_MINUS_EYE_TRANSLATE: any;
  private DOFS_EYE_AND_OVERLAY_MINUS_EYE_TRANSLATE: any;
  private DOFS_TO_CENTER: any;

  /**
   * Constructs (but does not init) Embodied Listen instance
   *
   * @param {EmbodiedDialog} _ed
   */
  constructor(private _ed: EmbodiedDialog) {
    super();
  }

  /**
   * Initializes Embodied Listen instance
   *
   * @param {jibo} jibo instance
   * @param {boolean} [debug=false] Toggle debug mode
   * @returns {Promise<void>} Resolved when completed initialization
   */
  async init(jibo: typeof JiboImport, debug=false): Promise<void> {

    if (jibo) {
      this._jibo = jibo;
    } else {
      throw new Error('Cannot instantiate without Jibo instances!');
    }

    const dofs = this._jibo.expression.dofs;
    this.DOFS_ALL_MINUS_EYE_TRANSLATE = dofs.ALL.minus(dofs.EYE_TRANSLATE);
    this.DOFS_EYE_AND_OVERLAY_MINUS_EYE_TRANSLATE = (dofs.EYE.plus(dofs.OVERLAY)).minus(dofs.EYE_TRANSLATE);
    this.DOFS_TO_CENTER = dofs.ALL.minus(dofs.LED).minus(dofs.BODY).minus(dofs.EYE_TRANSLATE);

    this._debug = debug;

    // Wait for for Jibo's face to be initialized before trying to load animations into cache
    jibo.timer.once('update', () => {
      log.debug('Caching core Embodied Listen animations.');
      const seePerson = true;
      const eyeStyles = [EyeTransitionStyle.POP, EyeTransitionStyle.BLINK];
      const dir = EyeTransitionDirection.TO;
      const listening = true;
      const useSound = false;

      // Load all perceptual eye animations into CacheUtils.
      eyeStyles.forEach(async styleKey => {
        let anim: string;
        try {
          anim = AnimSelector.getPerceptualEyeTransition(seePerson, styleKey, dir, useSound);
          await EmbodiedUtils.loadAnimationIntoCache(jibo, anim, CacheUtils.GlobalCacheName);
          anim = AnimSelector.getPerceptualEyePose(seePerson, listening);
          await EmbodiedUtils.loadAnimationIntoCache(jibo, anim, CacheUtils.GlobalCacheName);
        } catch (err) {
          log.warn(`Unable to load animation  ${anim}  into cache  ${CacheUtils.GlobalCacheName}`);
        }
      });
    });

    // Connect all (non-transitional) states to the reset state
    [
      this._hjExpression,
      this._nonHjExpression,
      this._offExpression,
      this._engage,
      this._listening,
      this._thinking,
      this._waitForAnimFinish,
    ].forEach( state => {
      state.addTypedEventTransition(this.eventsInternal.reset, this._reset);
    });

    /*
     * Reset state
     */
    this._reset.addDoneTransition(this._idle);
    this._reset.onEntry = async () => {
      log.debug('Entering Reset');
      // TODO: If EL ever adds back more animations other than Listening Expressions, we may
      // need to re-evaluate how we handle resetting the stage
      this._queue.clear();

      const waitResult = await timeout(this._queue.waitUntilEmpty(), TIMEOUT, {
        log: log,
        logMessage: 'embodiedListen.animQueue.waitUntilEmpty',
        timeoutValue: ANIM_CLEAR_TIMEOUT
      });
      if (typeof waitResult === 'string') {
        if (waitResult === ANIM_CLEAR_TIMEOUT) {
          this._queue = new PromiseQueue();
        }
      }

      if (this._reset.isCurrent()) {
        Utils.setLED(this._jibo, Led.OFF);
        await this.stopListeningEye();
      }
    };

    /*
     * Idle state
     */
    const updateBind = this.update.bind(this);
    // Make sure that this update handler does not get subjected to the same cleanup
    // criteria as those created in skills.
    updateBind.isGlobalTimer = true;

    this._idle.addTypedEventTransition(this.eventsIn.hjHeard, this._hjExpression);
    this._idle.addTypedEventTransition(this.eventsIn.startListen, this._nonHjExpression);
    this._idle.addTypedEventTransition(this.eventsInternal.enterActiveMode, this._active);
    this._idle.onEntry = () => {
      log.debug('Entering Idle');
      this._jibo.performance.log('EmbodiedListenReturnedToIdleSkill');
      this.eventsOut.finished.emit();
      this._jibo.timer.removeListener('update', updateBind);
      if (this._pendingActiveMode) {
        this.eventsInternal.enterActiveMode.emit();
      }
    };
    this._idle.onExit = () => {
      log.debug('Exiting Idle');
      this._jibo.timer.on('update', updateBind);
    };

    /*
     * Active Mode State
     */
    this._active.addTypedEventTransition(this.eventsInternal.exitActiveMode, this._idle);
    this._active.addTypedEventTransition(this.eventsInternal.enterActiveMode, this._active);
    this._active.addTypedEventTransition(this.eventsIn.hjHeard, this._hjExpression);
    this._active.onEntry = () => {
      this._activeMode = this._pendingActiveMode;
      this._pendingActiveModeExtPr.resolve(RequestStatus.SUCCEEDED);
      this._pendingActiveMode = null;

      log.debug(`Entering Active Mode: ${this._activeMode}`);
      switch (this._activeMode) {
          case ActiveListenMode.UI:
              Utils.setLED(this._jibo, Led.LISTENING);
              break;
          case ActiveListenMode.OPTIONAL_RESPONSE:
              Utils.setLED(this._jibo, Led.LISTENING_OR);
              this.startListeningEye(true);
              break;
      }
    };
    this._active.onExit = async () => {
      log.debug(`Exiting Active Mode: ${this._activeMode}`);
      switch (this._activeMode) {
          case ActiveListenMode.UI:
              Utils.setLED(this._jibo, Led.OFF);
              break;
          case ActiveListenMode.OPTIONAL_RESPONSE:
              Utils.setLED(this._jibo, Led.OFF);
              await this.stopListeningEye();
              break;
      }
      this._activeMode = null;
    };

    /*
     * Wait for anim finish state
     * In this state we wait for all animations to have finished playing before returning
     * to Idle
     */
    this._waitForAnimFinish.addInternalTransition('Finished', this._idle);
    this._waitForAnimFinish.onEntry = () => {
      log.debug('Entering Wait for Anim Finished');
      this._jibo.performance.log('EmbodiedListenWaitForAnimFinishSkill');

      if (USE_CENTER_ROBOT) {
        this._addAnimToQueue( () => {
          return this._jibo.expression.centerRobot({
              requestor: EmbodiedListen.NONHJ_OWNER_INFORMATION,
              dofs: this.DOFS_TO_CENTER,
              centerGlobally: false
          });

      	});
      }

      this._queue.waitUntilEmpty()
        .then(() => {
          if (this._waitForAnimFinish._isCurrent) {
            this._waitForAnimFinish.transitionTo(this._idle);
          }
        }).catch(e => {
          log.error(e);
          if (this._waitForAnimFinish._isCurrent) {
            this._waitForAnimFinish.transitionTo(this._idle);
          }
        });
    };

    this._offExpression.addDoneTransition(this._waitForAnimFinish);
    this._offExpression.addTypedEventTransition(this.eventsIn.hjHeard, this._hjExpression);
    this._offExpression.onEntry = async () => {
      log.debug('Entering Off Expression');
      Utils.setLED(jibo, Led.OFF);
      await this.stopListeningEye();
    };

    /*
     * HJ Expression state setup
     * In this state we turn on LED, play sound and Eye and wait until we have oriented
     * towards source of HJ sound
     */
    this._hjExpression.addTypedEventTransition(this.eventsIn.oriented, this._engage);
    this._hjExpression.addTypedEventTransition(this.eventsIn.cloudFinished, this._offExpression);
    this._hjExpression.addInternalTransition('Disable once', this._idle);
    this._hjExpression.onEntry = () => {
      // const now = Date.now();
      log.debug('Entering HJ Expression (Eye+LED)');
      this._jibo.performance.log('EmbodiedListenStartingHJHeardSkill');
      if (this._disableOnce) {
        this._disableOnce = false;
        this._hjExpression.transitionTo(this._idle);
      }
      else {
        switch (this._ambientMode) {
          case AmbientListenMode.NORMAL:
          case AmbientListenMode.NO_BODY:
            Utils.setLED(this._jibo, Led.LISTENING);
            // We play the "huh" sound no more than once every X minutes
            // if ((now - this._lastHJSoundTime) > HJ_SOUND_INTERVAL) {
            //   this._lastHJSoundTime = now;
            //   Utils.playSound(this._jibo, Sound.ON);
            // }
            this.startListeningEye(true);
            break;
        }
      }
    };

    /*
     * Non HJ Expression state
     * In this state we turn on LED and Eye and immediately move on
     */
    this._nonHjExpression.addInternalTransition('ES Dispatch Done', this._engage);
    this._nonHjExpression.addInternalTransition('Disable once', this._idle);
    this._nonHjExpression.addTypedEventTransition(this.eventsIn.cloudFinished, this._offExpression);
    this._nonHjExpression.addTypedEventTransition(this.eventsIn.hjHeard, this._hjExpression);
    this._nonHjExpression.onEntry = () => {
      log.debug('Entering non-HJ Expression (Eye+LED)');
      this._jibo.performance.log('EmbodiedListenStartingNonHJSkill');
      if (this._disableOnce) {
        this._disableOnce = false;
        this._nonHjExpression.transitionTo(this._idle);
      } else {
        switch (this._ambientMode) {
          case AmbientListenMode.NORMAL:
          case AmbientListenMode.NO_BODY:
            Utils.setLED(this._jibo, Led.LISTENING);
            this.startListeningEye(true);
            break;
        }
        this._ed.speech.waitForAnimDispatch().then( () => {
          if(this.current === this._nonHjExpression) {
            this._nonHjExpression.transitionTo(this._engage);
          }
        });
      }
    };

    /*
     * Engage state setup
     * In this state we play the engaged animation and wait for incremental results
     */
    this._engage.addTypedEventTransition(this.eventsIn.sos, this._listening);
    this._engage.addTypedEventTransition(this.eventsIn.eos, this._thinking);
    this._engage.addTypedEventTransition(this.eventsIn.cloudFinished, this._offExpression);
    this._engage.addTypedEventTransition(this.eventsIn.hjHeard, this._hjExpression);
    let nextBlinkTime = -1;
    this._engage.onEntry = () => {
      log.debug('Entering Engage');
      nextBlinkTime = Date.now() + 2000; // Next blink in 2sec
      switch (this._ambientMode) {
        case AmbientListenMode.NORMAL:
          // this._addAnimToQueue(Anims.ENGAGE);
          break;
        case AmbientListenMode.NO_BODY:
          // this._addAnimToQueue(Anims.ENGAGE, AnimConfigs.NO_BODY);
          break;
      }
    };
    // Perform blinks
    this._engage.onUpdate = () => {
      let now = Date.now();
      if (now >= nextBlinkTime) {
        nextBlinkTime = now + Math.floor(2500 + Math.random() * 1000);
        // this._addAnimToQueue(Anims.BLINK);
      }
    };
    this._engage.onExit = () => {
      switch (this._ambientMode) {
        case AmbientListenMode.NORMAL:
          // this._addAnimToQueue(Anims.DISENGAGE);
          break;
        case AmbientListenMode.NO_BODY:
          break;
      }
    };

    /*
     * Listening state setup
     * In this state we simply listen and every now and then we bob our head or shift posture
     */
    this._listening.addTypedEventTransition(this.eventsIn.eos, this._thinking);
    this._listening.addTypedEventTransition(this.eventsIn.cloudFinished, this._offExpression);
    this._listening.addTypedEventTransition(this.eventsIn.hjHeard, this._hjExpression);
    let incrementalHandler = this._handleIncremental.bind(this);
     this._listening.onEntry = () => {
      log.debug('Entering Listening');
      this.eventsIn.sos.on(incrementalHandler);
    };
    this._listening.onExit = () => {
      this.eventsIn.sos.removeListener(incrementalHandler);
    };

    /**
     * Thinking state setup
     * In this state we turn off LED and Eye and start a thinking animation to hide the
     * wait time until we receive cloud results
     */
    this._thinking.addTypedEventTransition(this.eventsIn.cloudFinished, this._waitForAnimFinish);
    this._thinking.addTypedEventTransition(this.eventsIn.hjHeard, this._hjExpression);
    this._thinking.onEntry = async () => {
      log.debug('Entering Thinking (+ Off Expression)');
      // this._addAnimToQueue(Anims.THINKING);
      Utils.setLED(jibo, Led.OFF);
      await this.stopListeningEye();
    };
  }

  /**
   * Disposes of resources, unsubscribes from events.
   * Should be called when destroying instance.
   */
  dispose() {
      //currently nothing to do
  }

  /**
   * Resolves immediately if already in idle, otherwise waits until state machine reaches idle.
   * Can be fast forwarded to Idle. In this case we will flush animation queue and head straight to idle.
   * @param {boolean} fastForward Fast forward state sequence to idle state
   * @returns {Promise}
   */
  waitForIdle(fastForward = false): Promise<any> {
    if (this.current === this._idle) {
      return Promise.resolve();
    }
    else {
      return new Promise( resolve => {
        this.eventsOut.finished.once(resolve);
        if (fastForward) {
          this.eventsInternal.reset.emit();
        }
      });
    }
  }

  /**
   * This method demonstrates the animation/led/sound used in both
   * the engagement and disengagement states.
   * @param {boolean} turnOn Whether to turn on engaged state or turn it off
   * @returns {Promise<T[]>}
   */
  demoEngaged(turnOn: boolean) {
    if (turnOn) {
      Utils.setLED(this._jibo, Led.LISTENING);
      return Promise.all([this.startListeningEye(true)]);
    }
    else {
      Utils.setLED(this._jibo, Led.OFF);
      return Promise.all([this.stopListeningEye()]);
    }
  }

  /**
   * Disables Embodied Listen for the next listen event
   */
  public disableOnce() {
    this._disableOnce = true;
  }

  /**
   * Returns the current Ambient Embodied Listen Mode
   * @return {AmbientListenMode}
   */
  getAmbientMode(): AmbientListenMode {
    return this._ambientMode;
  }

  /**
   * Returns the current Active Embodied Listen Mode
   * @return {ActiveListenMode}
   */
  getActiveMode(): ActiveListenMode {
    return this._activeMode;
  }

  /**
   * Changes the Ambient Embodied Listen Mode
   * @param {AmbientListenMode} mode New mode
   */
  setAmbientMode(mode: AmbientListenMode): void {
    const newMode = AmbientListenMode[mode];
    if (!newMode) {
      log.warn(`Requested invalid Ambient Listen Mode '${mode}'`);
    } else {
      this._ambientMode = newMode;
    }
  }

  /**
   * Request to enter an Active Embodied Listen Mode
   * @param {ActiveListenMode} mode - Requested Active Mode.
   * @param {ActiveModeOptions} [options] - Configuration Options consumed by the different Active Modes
   * @return {Promise<RequestStatus>} Resolves once Embodied Listen is back
   * in requested Active Mode or interrupted by another active mode request.
   */
  enterActiveMode(mode: ActiveListenMode, options?: ActiveModeOptions): Promise<RequestStatus> {
    const newMode = ActiveListenMode[mode];
    if (!newMode) {
      log.warn(`Requested invalid Active Listen Mode '${mode}'`);
      return Promise.resolve(RequestStatus.REJECTED);
    } else {
      if (this._activeMode) {
        if (newMode !== this._activeMode) {
          this._pendingActiveMode = newMode;
          this._pendingActiveModeExtPr = new ExtPromise<RequestStatus>();
          this.eventsInternal.enterActiveMode.emit();
          return this._pendingActiveModeExtPr.promise;
        } else {
          return Promise.resolve(RequestStatus.SUCCEEDED);
        }
      } else {
        if (this._pendingActiveMode) {
          this._pendingActiveMode = null;
          this._pendingActiveModeExtPr.resolve(RequestStatus.INTERRUPTED);
        }
        this._pendingActiveMode = newMode;
        this._pendingActiveModeExtPr = new ExtPromise<RequestStatus>();
        this.waitForIdle(true);  // FastForward to Idle, but don't wait for it
        this.eventsInternal.enterActiveMode.emit();
        return this._pendingActiveModeExtPr.promise;
      }
    }
  }

  /**
   * Request to exit the Active Embodied Listen Mode
   * @param {ListenMode|string} mode New mode
   * @param {boolean} [fastForward=true] `true` to fast forward state sequence to idle state.
   * @return {Promise<void>} Resolves once Embodied Listen is back in idle state.
   */
  exitActiveMode(fastforward=true): Promise<void> {
    if (this._activeMode) {
      if (this._pendingActiveMode) {
        this._pendingActiveMode = null;
        this._pendingActiveModeExtPr.resolve(RequestStatus.CANCELLED);
      }
      this.eventsInternal.exitActiveMode.emit();
      return this.waitForIdle(fastforward);
    } else {
      return Promise.resolve();
    }
  }

  /**
   * Triggers a listening eye transition
   * @param {boolean} heyJibo - Whether we are transitioning because of a HJ event
   * @internal
   * @private
   */
  private startListeningEye(heyJibo: boolean) {
    const seePerson = true;
    const dir = EyeTransitionDirection.TO;
    const useSound = false;
    const now = Date.now();
    // const seePerson = (this.perceptualState === VisualPerceptionState.PERSON);
    // const debugEnding = this.debugPerceptualEye ? '-debug' : '';

    if (this.listenState !== ListeningState.LISTENING) {
      this.listenState = ListeningState.LISTENING;

      // Transition to person listening with HJ
      if (heyJibo && ((now - this._lastHJBlinkTime) > HJ_BLINK_INTERVAL)) {
        this._lastHJBlinkTime = now;
        this.addEyeAnimationToQueue(AnimSelector.getPerceptualEyeTransition(seePerson, EyeTransitionStyle.BLINK, dir, useSound), heyJibo);
      } else {
        this.addEyeAnimationToQueue(AnimSelector.getPerceptualEyeTransition(seePerson, EyeTransitionStyle.POP, dir, useSound), heyJibo);
      }
      //this.addEyeAnimationToQueue(AnimSelector.getPerceptualEyePose(seePerson, true) + debugEnding);
    }
  }

  /**
   * Triggers a listening eye (off)
   * @internal
   * @private
   */
  private async stopListeningEye(): Promise<any> {
    // const debugEnding = this.debugPerceptualEye ? '-debug' : '';
    // const dir = EyeTransitionDirection.FROM;
    // const seePerson = this.perceptualState === VisualPerceptionState.PERSON;

    if (this.listenState !== ListeningState.NOT_LISTENING) {
      this.listenState = ListeningState.NOT_LISTENING;

      // Transition to person listening with HJ
      //this.addEyeAnimationToQueue(AnimSelector.getPerceptualEyeTransition(seePerson, EyeTransitionStyle.BLINK, dir), true);
      //this.addEyeAnimationToQueue(AnimSelector.getPerceptualEyePose(seePerson, false) + debugEnding);
      await this._jibo.expression.cleanup({
        requestor: EmbodiedListen.HJ_OWNER_INFORMATION,
        dofs: this.DOFS_TO_CENTER
      });
    }
  }

  /**
   * Handles incremental results and is used to create a head bob or a blink
   * or posture shift
   * @internal
   * @private
   */
  private _handleIncremental() {
    if (this._ambientMode !== AmbientListenMode.NO_BODY) {
      const now = Date.now();
      if (now - this._lastHeadBob > this._nextHeadBob) {
        this._nextHeadBob = Math.floor(1000 + Math.random() * 1000);
        this._lastHeadBob = now;
        // const anim = _.sample(Anims.HEAD_BOB);
        // this._addAnimToQueue(anim);
      }
    }
  }

  private addEyeAnimationToQueue(name: string, heyJibo=false) {
    // AnimConfig
    const baseConfig = {
      cache: CacheUtils.GlobalCacheName,
      dofs: this.DOFS_EYE_AND_OVERLAY_MINUS_EYE_TRANSLATE,
    };
    const nonhjConfig = Object.assign({}, baseConfig, { layer: "beat" });
    const config = heyJibo ? baseConfig : nonhjConfig;

    // PlaybackOptions
    const baseOptions: PlaybackOptions = {
      screenCenterOverride: true,
      disableSetFaceAnim: true
    };
    const hjOptions: PlaybackOptions = Object.assign({}, baseOptions, {
      ownerInformation: EmbodiedListen.HJ_OWNER_INFORMATION,
      disableSetFaceAnim: false,
    });
    const options = heyJibo ? hjOptions : baseOptions;

    this._addAnimToQueue(name, config, options);
  }

  /**
   * Internal mode setter, gets called by `setMode`
   * @param {string|PromiseProvider} anim to play
   * @param {AnimConfig} [config] to configure the anim
   * @param {PlaybackOptions} [options] to configure the playback
   * @private
   */
  private _addAnimToQueue(anim: string|PromiseProvider, config?: AnimConfig, options?: PlaybackOptions) {
    if (typeof anim === 'function') {
      this._queue.add(anim);
    } else {
      this._queue.add( async () => {
        const playbackResult = Utils.playAnimation({
          jibo: this._jibo,
          animName: anim as string,
          config: config,
          options: options,
        });
        this._lastAnimInstance = playbackResult.playback;
        return playbackResult.result;
      });
    }
  }
}
