/*
 * @fileOverview
 * An auto rule which wraps an utterance in an set of SSML tags that match his emotional state
 */

import JiboImport = require('../../../../../../jibo');  // Just for typings, not available at runtime
type Emotion = JiboImport.emotion.Emotion;
type EmotionName = JiboImport.emotion.EmotionName;


import Node from 'jibo-node-xml';
import { InputProcessor } from '../../InputProcessor';
import { SSMLNodeType, SSMLStyleTagType, SSMLNodeConfig } from '../../../common/Types';
import { TagTreeNode } from '../../TagTreeNode';
import { TimelineAutoRule } from './TimelineAutoRule';
import { TimelineAutoRuleInsertionInfo, TimelineAutoRuleMatchInfo, TimelineAutoRuleType, TimelineModUtils } from './TimelineModUtils';
import { TimelineModifyingRuleNames } from '../AutoRuleManager';


export class EmotionalVoiceRule extends TimelineAutoRule {

    private emotionToVoiceConfig = new Map<EmotionName, SSMLNodeConfig[]>();
    private emotion: Emotion;

    /**
     * @param {jibo} jibo
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(private jibo: typeof JiboImport, priority = 1, probability = 1) {
        super(TimelineModifyingRuleNames.EmotionalVoice, TimelineAutoRuleType.TIMELESS, priority, probability);

        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.NEUTRAL, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.NEUTRAL
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.INSECURE, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.CONFUSED
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.FRUSTRATED, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.CONFUSED
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.HOPEFUL, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.CONFIDENT
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.JOYFUL, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.ENTHUSIASTIC
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.PLEASED, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.ENTHUSIASTIC
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.DETERMINED, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.SHEEPISH
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.SAD, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.SHEEPISH
                }
            }
        ]);
        this.emotionToVoiceConfig.set(jibo.emotion.EmotionName.CONFIDENT, [
            {
                type: SSMLNodeType.STYLE,
                attrs: {
                    set: SSMLStyleTagType.CONFIDENT
                }
            }
        ]);
    }

    /**
     * Create (possibly nested) set of SSML Nodes as prescribed in the emotionToVoiceConfig map
     *
     * @param {TimelineAutoRuleMatchInfo} matchInfo
     * @return {Array<Node, TimelineAutoRuleInsertionInfo>}
     * @private
     */
    _createTimelineModifyingData(matchInfo: TimelineAutoRuleMatchInfo): [Node, TimelineAutoRuleInsertionInfo] {
        let voiceConfig = this.emotionToVoiceConfig.get(this.emotion.name);
        if (!voiceConfig) {
            voiceConfig = this.emotionToVoiceConfig.get(this.jibo.emotion.EmotionName.NEUTRAL);
        }
        const ssmlNodesToInsert = voiceConfig.map(ssmlConfig => TimelineModUtils.SSMLNodeBuilder(ssmlConfig.type, ssmlConfig.attrs));
        const parent = matchInfo.children[0].parents[0];
        const insertionInfo: TimelineAutoRuleInsertionInfo = {
            nodes: ssmlNodesToInsert,
            children: matchInfo.children
        };
        return [parent, insertionInfo];
    }

    /**
     * Gathers all nodes that are wrappable with a TTSSML Style tag (which is either all or none)
     *
     * @param {TagTreeNode} xmlTree
     * @return {Array<Array<Node, string>>} Nodes that match and which rule was matched
     * @private
     */
    _applyInternal(xmlTree: TagTreeNode): TimelineAutoRuleMatchInfo[] {
        let matchesInfo: TimelineAutoRuleMatchInfo[] = [];
        this.emotion = this.jibo.emotion.getNearestEmotion();

        const allNodes = xmlTree.gatherDescendants();
        const containsTimelessSSML = allNodes.every(node => !InputProcessor.isTimelessSSML(node));
        if (containsTimelessSSML) {
            matchesInfo.push({
                children: xmlTree.gatherChildren()
            });
        }

        return matchesInfo;
    }

}
