// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../../../jibo');
// ------------------------------------------------
import Node from 'jibo-node-xml';
import { NodeType, Parser } from 'jibo-node-xml';
import { TagTreeNode } from './TagTreeNode';
import { AssetNode } from './AssetNode';
import { ContentValidator } from './ContentValidator';
import { ESTreeType, NLPNodeType, SSMLNodeType, AssetNodeType } from '../common/Types';
import { SSMLNode } from './SSMLNode';
import { NLPTools } from '../utils/NLPTools';
import { WordNode } from './parsers/NLParser';
import { Lexer } from './parsers/Lexer';
import {
  TimelineAutoRuleData,
  TimelineAutoRuleInsertionInfo,
  TimelineAutoRuleType
} from './auto_rules/timeline_mod/TimelineModUtils';

import { speechLog } from '../../log';
const log = speechLog.createChild("InputProcessor");

/**
 * The group of tags that are acted upon/turned into their own Node types
 */
export const TagAttributes = {
  NON_BLOCKING: 'nonBlocking',
  END_NEUTRAL: 'endNeutral'
};

export class InputProcessor {

  private _lexer: Lexer;
  private contentValidator: ContentValidator;
  // Map from swear to SSML tag replacement (currently same is used for all)
  private swearToTags = {
    ALL: `<break size='0.1'/> <pitch band='0.0'> <pitch add="4000"> <duration set="0.5"> e </duration> </pitch> </pitch> <break size='0.1'/>`
  };

  /**
   *
   * @param {Jibo} jibo the jibo singleton
   */
  constructor(jibo: typeof JiboImport) {
    this._lexer = new Lexer(jibo);
    this.contentValidator = new ContentValidator();
  }

  /**
   * Takes a text string sentence (optionally annotated with XML) and converts
   * it into a "pre-input tree" -- a more processed intermediary tree used by
   * other parts of the pipeline
   *
   * @param  {String} sentence A text sentence optionally annotated with XML.
   *   e.g. `Mary had a <anim cat="emphasis">little</anim> lamb.`
   * @param  {boolean} [censorSwears=true] Swap out swears for a set of tags that act as a censor
   * @return {TagTreeNode} Parsed word tree structure
   */
  async generatePreInputTree(sentence: string, censorSwears=true): Promise<TagTreeNode> {

    if (censorSwears) {
      const replaced = this.contentValidator.replaceRestricted(sentence, this.swearToTags.ALL);
      if (sentence !== replaced) {
        log.warn('Requested TTS contains restricted content! It has been censored.');
      }
      sentence = replaced;
    }

    let xmlTree: TagTreeNode = <TagTreeNode> Parser.parseXML(sentence);
    xmlTree.forEachDescendant( node => {
      node.type = node.type.toUpperCase();
    });

    // Swap out all break nodes for real SSML break nodes
    xmlTree.forEachDescendantType(SSMLNodeType.BREAK, node => {
      if (node.parents.length === 1) {  // Sanity check, should only have 1 parent
        const parent = node.parents[0];
        const selfIndex = parent.children.indexOf(node);
        const size = node.getNumberAtt('size');
        let properSSMLNode = new SSMLNode(SSMLNodeType.BREAK);
        properSSMLNode.setAttribute('size', size);
        parent.children.splice(selfIndex, 1, properSSMLNode);
        properSSMLNode.parents.push(parent);
        node.clearParents();
      } else {
        throw new Error('Unexpected number of parents to SSML Break Node.');
      }
    });

    let textNodes = xmlTree.gatherDescendantsType(NodeType.TEXT);
    xmlTree.expansions = [];
    xmlTree.contractions = [];

    for (let textNode of textNodes) {
      let sanitizedText = NLPTools.cleanInput(textNode.value);
      let preExpanded = await this._lexer.lex(sanitizedText);
      let newNodes = [];
      preExpanded.forEach( token => {
        let [localExp, localContr] = NLPTools.getExpansionsAndContractions(token);
        xmlTree.expansions.push(...localExp);
        xmlTree.contractions.push(...localContr);
        localExp.forEach( exp => {
          let node = new Node(NodeType.TEXT, exp);
          newNodes.push(node);
        });
      });

      textNode.parents.forEach( parent => {
        let positionIndex = parent.children.indexOf(textNode);
        if (positionIndex === -1) {
          throw new Error('Parent node missing reference to child.');
        } else {
          // Remove the original node.
          parent.children.splice(positionIndex, 1);
          // Add new child nodes.
          for (let newNode of newNodes) {
            newNode.parents = textNode.parents.slice();
            parent.children.splice(positionIndex, 0, newNode);
            positionIndex++;
          }
        }
      });
    }

    // Set some basic information on the root node.
    xmlTree.value = sentence;
    xmlTree.treeType = ESTreeType.TAG_TREE;
    xmlTree.textValue = InputProcessor.getPlainTextFromTree(xmlTree);
    return xmlTree;
  }

  /**
   * Given all matching TimelineAutoRuleData, insert the timeline modifying autoRule assets into the
   * XML tree representation of the text.
   *
   * @param {TagTreeNode} xmlTree
   * @param {TimelineAutoRuleData} timelineAutoRuleData
   */
  insertTimelineAutoRules(xmlTree: TagTreeNode, timelineAutoRuleData: TimelineAutoRuleData[]) {

    // Separate the TTSSML rules from those that explicitly affect the timeline (e.g. blocking anims, SSML breaks)
    const timefulMatches = timelineAutoRuleData.filter( ruleData => {
      return ruleData.type === TimelineAutoRuleType.TIMEFUL;
    });
    const timelessMatches = timelineAutoRuleData.filter(ruleData => {
      return ruleData.type === TimelineAutoRuleType.TIMELESS;
    });

    // First, insert all timeline modifying animations and break nodes
    // Merge all AutoRules to be considered by parent (necessary to guarantee proper timeline insertion)
    let parentMerged: Map<Node, TimelineAutoRuleInsertionInfo[]> = new Map<Node, TimelineAutoRuleInsertionInfo[]>();
    timefulMatches.forEach( ruleData => {
      ruleData.matches.forEach((matchInfo, parent) => {
        let childrenToInsert: TimelineAutoRuleInsertionInfo[] = parentMerged.get(parent);
        if (!childrenToInsert) {
          childrenToInsert = [];
          parentMerged.set(parent, childrenToInsert);
        }
        childrenToInsert.push(...matchInfo);
      });
    });

    parentMerged.forEach( (matchInfo, parent) => {
      // Sort the matches to insert so that we insert them left to right to maintain the index offset as we insert
      matchInfo.sort( (a, b) => {
        return a.offset - b.offset;
      });

      let insertedNodeCount = 0;
      matchInfo.forEach(content => {
        content.nodes.forEach(node => {
          parent.children.splice((content.offset + insertedNodeCount), 0, node);
          insertedNodeCount++;
        });
      });
    });

    // Second, insert all TTSSML tag nodes and re-order the tree accordingly
    timelessMatches.forEach(ruleData => {
      ruleData.matches.forEach((matchInfo, parent) => {
        matchInfo.forEach(content => {
          let workingChild: Node;
          let shouldBeInsertedCount = 0;
          while (content.nodes.length > 0) {
            const innermost = content.nodes.pop();
            if (!workingChild && shouldBeInsertedCount < 1) {
              const parentCheck = content.children.every(child => child.parents[0] === parent);
              const firstChildIdx = parent.children.indexOf(content.children[0]);
              if (parentCheck && (firstChildIdx > -1)) {
                parent.children.splice(firstChildIdx, 0, innermost);  // Add innermost node as a child to parent
                content.children.forEach(child => {  // Move all children to be children of innermost node
                  child.clearParents();
                  innermost.addChild(child);
                });
                innermost.parents.push(parent);
                parent.children.splice(firstChildIdx + 1, content.children.length);  // Remove all other children as children from old parent
                workingChild = innermost;
              }
            } else if (workingChild && shouldBeInsertedCount > 0) {
              const workingChildIdx = parent.children.indexOf(workingChild);
              parent.children.splice(workingChildIdx, 0, innermost);  // Add next innermost node as a child
              workingChild.clearParents();
              innermost.addChild(workingChild);
              parent.children.splice(workingChildIdx + 1, 1);  // Remove working child as child from old parent
              innermost.parents.push(parent);
              workingChild = innermost;
            } else {
              break;  // Something changed in the expected state of the nodes; skip to next rule match
            }
            shouldBeInsertedCount++;
          }
        });
      });
    });

    return xmlTree;
  }

  /**
   * Merges pre-input with nlp tree and produces an 'Input Tree' which splits
   * on blocking nodes and only contains TTS and ANIM top level nodes
   * @param {Node} inputTree that contains all the tag XML hierarchy
   * @param {Node} nlpTree that contains the word information
   * @return {Node} InputTree
   */
  static generateInputTree(inputTree: TagTreeNode, nlpTree: Node): Node {

    InputProcessor.replaceTreeTextNodes(nlpTree, inputTree, true);

    let assetNodes: Node[] = inputTree.gatherDescendants( node => {
      return InputProcessor.isAsset(node);
    });

    // Swap out asset nodes for real Asset nodes
    assetNodes.forEach( (assetNode: AssetNode) => {
      if (assetNode.metaFilter === undefined) {
        let newAssetNode = new AssetNode(assetNode.type, assetNode.att);
        InputProcessor._createSubTree(newAssetNode, assetNode.children);

        for (let parent of assetNode.parents) {
          // Swap out the assetNode among parent's children
          let positionIndex = parent.children.indexOf(assetNode);
          if (positionIndex === -1) {
            throw new Error('Parent doesn\'t not recognize child.');
          }
          parent.children.splice(positionIndex, 1, newAssetNode);
        }
      }
    });

    // Swap back in contractions / prune extraneous expanded contraction words
    const words = inputTree.gatherDescendantsType(NLPNodeType.WORD) as WordNode[];
    for (let idx = (words.length - 1); idx >= 0; idx--) {
      const word = words[idx];
      let isContraction = word.getAttribute('contraction') as string;
      if (isContraction) {
        word.value = isContraction;
      } else if (word.contractionBase) {
        for (let parent of word.parents) {
          // Prune expanded contraction words
          let positionIndex = parent.children.indexOf(word);
          if (positionIndex !== -1) {
            parent.children.splice(positionIndex, 1);
          }
        }
        word.clearParents();
      }
    }

    return inputTree;
  }

  /**
   * Create a new subtree with supplied root and list of Nodes
   *
   * @param {Node} root of sew subTree
   * @param {Node[]} nodesToAdd
   * @return {Node} Newly created subtree
   */
  static _createSubTree(root: any, nodesToAdd: Node[]) {

    nodesToAdd.forEach((node) => {
      node.clearParents(); // TODO: Really clear all parents?
      root.addChild(node);
    });

    return root;
  }

  /**
   * Checks whether a tag's type is 'asset' (i.e. an animation or sound).
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is asset.
   */
  static isAsset(node: Node): boolean {
    return AssetNodeType.hasOwnProperty(node.type);
  }

  /**
   * Checks whether a tag is empty (i.e. it has no children).
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is blocking.
   */
  static isEmpty(node: Node): boolean {
    return (node.children.length === 0);
  }

  /**
   * Checks whether a tag is blocking (e.g. a blocking animation or sound).
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is blocking.
   */
  static isBlocking(node: Node): boolean {
    return (InputProcessor.isAsset(node)) &&
           ((InputProcessor.isEmpty(node)) &&
            ((node.getAttribute(TagAttributes.NON_BLOCKING) !== 'true') ||
             (node.getAttribute(TagAttributes.NON_BLOCKING) === undefined)));
  }

  /**
   * Checks whether a tag is unbounded non-blocking (e.g. an empty non-blocking animation or sound).
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is unbounded and non-blocking.
   */
  static isUnboundedNonBlocking(node: Node): boolean {
    return (InputProcessor.isAsset(node)) &&
      (InputProcessor.isEmpty(node)) &&
      (InputProcessor.isExplicitlyNonBlocking(node));
  }

  /**
   * Checks whether a tag is explicitly non blocking (i.e. nonBlocking=true attribute).
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is blocking.
   */
  static isExplicitlyNonBlocking(node: Node): boolean {
    return (node.getAttribute(TagAttributes.NON_BLOCKING) === 'true');
  }

  /**
   * Checks whether a node/tag's type is SSML.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML.
   */
  static isSSML(node: Node): boolean {
    return InputProcessor.isTimefulSSML(node) ||
      InputProcessor.isTimelessSSML(node);
  }

  /**
   * Checks whether a node/tag's type is an SSML that has inherent timing value.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML.
   */
  static isTimefulSSML(node: Node): boolean {
    return InputProcessor.isBreak(node) ||
      InputProcessor.isSayAs(node);
  }

  /**
   * Checks whether a node/tag's type is an SSML that has no inherent timing value.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML.
   */
  static isTimelessSSML(node: Node): boolean {
    return InputProcessor.isPhoneme(node) ||
      InputProcessor.isPitch(node) ||
      InputProcessor.isDuration(node) ||
      InputProcessor.isStyle(node) ||
      InputProcessor.isEngine(node);
  }

  /**
   * Checks whether a node/tag's type is SSML Break.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML.
   */
  static isBreak(node: Node): boolean {
    return node.type === SSMLNodeType.BREAK;
  }

  /**
   * Checks whether a node/tag's type is SSML Phoneme.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML Phoneme.
   */
  static isPhoneme(node: Node): boolean {
    return node.type === SSMLNodeType.PHONEME;
  }

  /**
   * Checks whether a node/tag's type is SSML Pitch.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML Pitch.
   */
  static isPitch(node: Node): boolean {
    return node.type === SSMLNodeType.PITCH;
  }

  /**
   * Checks whether a node/tag's type is SSML Duration.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML Duration.
   */
  static isDuration(node: Node): boolean {
    return node.type === SSMLNodeType.DURATION;
  }

  /**
   * Checks whether a node/tag's type is SSML SayAs.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML SayAs.
   */
  static isSayAs(node: Node): boolean {
    return node.type === SSMLNodeType.SAY_AS;
  }

  /**
   * Checks whether a node/tag's type is SSML Style.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML Style.
   */
  static isStyle(node: Node): boolean {
    return node.type === SSMLNodeType.STYLE;
  }

  /**
   * Checks whether a node/tag's type is SSML Engine.
   *
   * @param {Node} node to check
   * @return {Boolean} Whether the supplied node is SSML Engine.
   */
  static isEngine(node: Node): boolean {
    return node.type === SSMLNodeType.ENGINE;
  }

  /**
   * Returns the text array contained within the tree.
   *
   * @param {Node} tree The XML tree to transform into a string.
   * @return {string[]} Array of text that composed of the tree's leaf node
   *   values.
   */
  static getPlainTextArrayFromTree(tree: Node): string[] {
    const textNodes = tree.gatherDescendantsType(NodeType.TEXT);
    return textNodes.map(node => node.value);
  }

  /**
   * Returns the text contained within the tree without any XML tags.
   *
   * @param {Node} tree The XML tree to transform into a string.
   * @return {String} A plain text string composed of the tree's leaf node
   *   values.
   */
  static getPlainTextFromTree(tree: Node): string {
    const wordArray = InputProcessor.getPlainTextArrayFromTree(tree);
    return NLPTools.joinWordsIntoSentence(wordArray);
  }

  /**
   * Returns the text (with SSML) contained within the tree.
   *
   * @param {Node} tree The XML tree to transform into a string.
   * @return {String} A plain text string composed of the tree's leaf node
   *   values.
   */
  static getSSMLTextFromTree(tree: Node): string {
    let textNodes = tree.gatherDescendants( node => {
      return (node.type === NodeType.TEXT) || (node.type === NLPNodeType.WORD) || (InputProcessor.isSSML(node));
    });

    return InputProcessor.getSSMLTextFromArray(textNodes);
  }

  /**
   * Returns the text (with SSML) contained within array of text nodes.
   *
   * @param {Node[]} textNodes The text nodes to transform into a string
   * @param {boolean} [prune=false] option to drop breaks that precede/succeed non-SSML text
   * @return {String} A plain text string composed of the array
   */
  static getSSMLTextFromArray(textNodes: Node[], prune=false): string {
    let stringifiedSSML = [];

    // Get the stringified SSML from the tree-as-array
    for (let idx = 0; idx < textNodes.length; idx++) {
      const terminal = InputProcessor._getSSMLTextRecursive(textNodes[idx], stringifiedSSML);
      const nextIdx = textNodes.indexOf(terminal);
      if (nextIdx < 0) {  // If we didn't find the terminal node in our original list of nodes (like a nonBlocking asset)
        break;  // We should have found all the nodes we care about recursively, so stop searching
      } else if (nextIdx > idx) {
        idx = nextIdx;
      }
    }
    return NLPTools.joinWordsIntoSentence(stringifiedSSML);
  }

  /**
   * Returns the text (with SSML) contained within array of text nodes.
   * ! Mutates !
   *
   * @param {Node} nodes Node to stringify
   * @param {string[]} stringified Properly stringified node results of current call
   * @return {Node} Terminal node
   * @private
   */
  static _getSSMLTextRecursive(node: Node, stringified: string[]): Node {
    let terminal: Node;  // The latest node in the current subtree that "has time"

    // If the current node has children, recursively retrieve all its children in proper order
    if (node.children.length) {
      let stringifiedRecur = [];  // The stringified SSML nodes
      if (!InputProcessor.isAsset(node)) {
        stringifiedRecur.push(node.toStringTagOnly());
      }
      for (let idx = 0; idx < node.children.length; idx++) {
        terminal = InputProcessor._getSSMLTextRecursive(node.children[idx], stringifiedRecur);
      }
      if (!InputProcessor.isAsset(node)) {
        stringifiedRecur.push(node.toStringClosingTag());
      }
      stringified.push(...stringifiedRecur);
    } else {  // Otherwise, if it's a terminal node
      // If the node is an animation, look for its TimeSync node to swap into the SSML
      if (InputProcessor.isAsset(node)) {
        if (InputProcessor.isBlocking(node) && (node as AssetNode).timeSyncNode) {
          node = (node as AssetNode).timeSyncNode;
        } else {
          return node;
        }
      }
      // Stringify terminal nodes
      if (node.type === NodeType.TEXT || node.type === NLPNodeType.WORD) {
        stringified.push(node.value);
      } else {
        stringified.push(node.toStringTagOnly());
      }
      terminal = node;
    }
    return terminal;
  }

  /**
   * Replaces a node's text nodes with another tree's text nodes.  The result
   * is two trees sharing the same text node instances.
   * @param {Node} sourceTree The tree with text nodes to retain.
   * @param {Node} destinationTree The tree with text nodes to replace.
   * @param {Boolean} optMatchWords Ensure that the words from both trees are
   *   matching.
   * @return {Node} The destination with the child text nodes replaced.
   */
  static replaceTreeTextNodes(sourceTree, destinationTree, optMatchWords?): Node {
    let srcTxtNodes = sourceTree.gatherDescendants(n => {
      return n.type === NLPNodeType.WORD || n.type === NodeType.TEXT;
    });

    let destTxtNodes = destinationTree.gatherDescendants(n => {
      return n.type === NLPNodeType.WORD || n.type === NodeType.TEXT;
    });

    if (optMatchWords) {
      let srcValues = srcTxtNodes.map(n => n.value).join(' ');
      let destValues = destTxtNodes.map(n => n.value).join(' ');
      if (srcValues !== destValues) {
        throw new TypeError(`Both trees must have the same words. ` +
          `SrcValues: ${srcValues}, DstValues: ${destValues}`);
      }
    }

    if (srcTxtNodes.length !== destTxtNodes.length) {
      throw new TypeError(`Must have same # of nodes in both trees. ` +
        `SrcValues: ${srcTxtNodes}, DstValues: ${destTxtNodes}`);
    }

    destTxtNodes.forEach((destNode, index) => {
      for (let parent of destNode.parents) {
        // Swap out the destNode of the equivalent srcNode.
        let positionIndex = parent.children.indexOf(destNode);
        if (positionIndex === -1) {
          throw new Error('Parent doesn\'t not recognize child.');
        }
        // Add src node to position and remove original in parent.
        parent.children.splice(positionIndex, 1, srcTxtNodes[index]);
        let parentIndex = destNode.parents.indexOf(parent);
        if (parentIndex === -1) {
          throw new Error('Node does not recognize parent');
        }
        destNode.parents.splice(parentIndex, 1);
        // Add parent to parents.
        srcTxtNodes[index].parents.push(parent);
      }
    });

    return destinationTree;
  }

  /**
   * Converts an annotation tree to a list of words.
   *
   * @param {Node} annotationTree The tree with tag annotations and words
   *   as their children.
   * @param {Boolean} ssml Whether the returned list should include SSML tags
   * @return {Node[]} List of word nodes.
   */
  static generateWordList(annotationTree: TagTreeNode, ssml?: boolean): Node[] {

    if (ssml) {
      annotationTree.forEachDescendant( (node) => {
        if (InputProcessor.isSSML(node)) {  // TODO: Fix Break nodes so they are like this automatically
          node.value = node.toString();
          node.type = NLPNodeType.WORD;
        }
      });
    }

    return annotationTree.gatherDescendants((node)=>{
      return node.type === <any> NLPNodeType.WORD as string ||
        node.type === <any> NodeType.TEXT as string;
    });
  }
}
