// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../../../jibo');
import AnimQuery = JiboImport.animDB.AnimQuery;
import AnimResults = JiboImport.animDB.AnimResults;
import AnimMetadata = JiboImport.animDB.AnimMetadata;
import AnimConfig = JiboImport.animDB.AnimConfig;
import Anim = JiboImport.animDB.Anim;
export type Animation = JiboImport.animDB.Animation;
export type TTSOptions = JiboImport.tts.TTSOptions;
// ------------------------------------------------

import * as _ from 'lodash/lodash.min';
import * as path from 'path';
import Node from 'jibo-node-xml';
import { MuteConfig } from 'jibo-common-types';
import { CacheUtils } from 'jibo-cai-utils';

import { Timeline } from './Timeline';
import { InputProcessor } from '../processing/InputProcessor';
import { AssetNode } from '../processing/AssetNode';
import { TimelineFrame } from './Timeline';
import { SSMLNode } from '../processing/SSMLNode';
import { AudioAnimTemplate } from '../processing/Formats';
import { AutoRuleNames } from '../processing/auto_rules/AutoRuleManager';
import {
  SpeakOptions,
  DispatchType,
  MetaLayerPresence,
  RequestType,
  NLPNodeType,
  AssetNodeType,
  SSMLNodeType,
  TTSTokenWord,
  TimeBounds,
  TTSFrame,
  AutoRuleMatch,
  TTSSpeakData,
  OptimalLoopResult
} from '../common/Types';

import { speechLog } from '../../log';
const log = speechLog.createChild("TimelineManager");

const TTS_PAU = '[lpau]';
const TTS_BREAK = '<break>';
const TTS_AUDIO_BREAK = '<audioBreak>';
const TTS_SAY_AS = '<say-as>';
const FRAME_RATE = 30.0;
const AUTORULE_GATE_RATE = 1.0;
const AUTORULE_ORIENTATION_PROBABILITY = 0.5;


export class AssetResolution {
  constructor (public resolved: boolean = false, public identifier: string = null, public reason: string = null) { }
}


export class TimelineManager {

  private _pathAssets: Map<Node, Animation>;
  private emojiCapReached: boolean;
  private _tempAnimationCollection = new this.jibo.animDB.AnimCollection((this.jibo.animDB as any)._animDB);

  constructor(private jibo: typeof JiboImport, private _resourceRoot, private _animResourceRoot?: string, private _audioResourceRoot?: string) {
    // noop
  }

  /**
   * Takes an InputTree and AutoTagTree and generates a Timeline composed of sound, animation and
   * TTS for later dispatch
   *
   * @param {Node} inputTree containing all user provided tag and NLP information
   * @param {SpeakOptions} options related to how the timeline should be constructed / expressed
   * @param {Node[]} autoTagTrees which contain which autorules match what word nodes
   * @return {Promise<Timeline>} Complete timeline of tts with requested and auto anims/sounds
   */
  generateTimeline(inputTree: Node, options: SpeakOptions, autoTagTrees?: Node[]): Promise<Timeline>  {

    this.emojiCapReached = false;

    return this._preProcessPathBasedAssets(inputTree)
      .then( pathAssets => {
        this._pathAssets = pathAssets;
        return this._inputTreeToTimeline(inputTree, options);
      })
      .then( timelineData => {
        const [timeline, wordSchedule] = timelineData;

        if (!autoTagTrees) {
          return Promise.resolve(timeline);
        } else {
          let pending: Map<number, AutoRuleMatch[][]> =
            this._autoTagTreesToPrioritizedTimelines(autoTagTrees, wordSchedule, timeline);

          return this._mergePendingWithMaster(pending, timeline);
        }
      });
  }

  /**
   * Takes an InputTree and creates a Timeline composed of requested sound, animation and TTS
   *
   * @param {Node} inputTree Itemized timing data retrieved from TTS service
   * @return {Node} pre-processed InputTree
   */
  async _preProcessPathBasedAssets(inputTree: Node): Promise<Map<Node, Animation>> {

    let pathAssetsPr: Promise<AnimMetadata>[] = [];
    let pathAssetMap = new Map<Node, Animation>();
    let cachedAssetMap = new Map<Node, Anim>();

    let pathAssets = <any> inputTree.gatherDescendants( node => {
      return InputProcessor.isAsset(node) && node.att.has('path');
    }) as AssetNode[];

    pathAssets.forEach( node => {
      let identifier = node.getAttribute('path') as string;

      if (node.type === AssetNodeType.ES) {
        const animPath = path.join(this._animResourceRoot, identifier);
        pathAssetsPr.push(new Promise( resolve => {
          this.jibo.animDB.AnimDBParser.parseAnimation(this.jibo, animPath, this._resourceRoot)
            .then(resolve)
            .catch( e => {
              resolve();
            });
        }));
      } else if (node.type === AssetNodeType.AUDIO) {
        const audioPath = this.jibo.utils.PathUtils.getAssetUri(identifier, undefined, this._audioResourceRoot);
        pathAssetsPr.push(new Promise( resolve => {
          identifier = path.join('audio', identifier);
          this.jibo.loader.load({
            type: 'sound',
            id: identifier,
            src: audioPath,
            complete: (err, loadedSound) => {
              if (err) {
                resolve();
              } else {
                resolve(this._getSoundMetadata(loadedSound, audioPath, node, cachedAssetMap));
              }
            }
          });
        }));
      }
    });

    try {
      const metaDatum = await Promise.all(pathAssetsPr);
      if (pathAssets.length === metaDatum.length) {
        let nodeAnimMetaZip = _.zip<any>(pathAssets, metaDatum) as [[AssetNode, AnimMetadata]];
        nodeAnimMetaZip.forEach(([node, metadata]) => {
          if (metadata) {
            if (metadata.path) {
              metadata.path = path.relative(this._resourceRoot, metadata.path);
            }
            let cached = cachedAssetMap.get(node);
            pathAssetMap.set(node, new this.jibo.animDB.Animation(this._tempAnimationCollection, metadata, this._resourceRoot, cached));
          }
        });
      } else {
        log.warn('Missing data about local (path-based) animation(s) or audio; unable to utilize in output.');
      }
    } catch (e) {
      log.warn(e);
    }
    return pathAssetMap;
  }

  /**
   * Takes a Sound object, parses it for duration, builds an Animation around it and returns the metadata
   *
   * @param {any} loadedSound Sounds referenced in <audio path='...' /> tag
   * @param {String} audioPath path to the audio file
   * @param {Node} node Asset node associated with the asset (anim) data
   * @param {Map<Node, Anim>} cachedAssetMap structure that holds cached animData objects
   * @return {AnimMetadata}
   */
  private _getSoundMetadata(loadedSound: any, audioPath: string, node: Node, cachedAssetMap: Map<Node, Anim>): AnimMetadata {
    let duration = Math.ceil(loadedSound.buffer.duration * FRAME_RATE);
    if (duration > 0) {
      let relAudioPath = path.relative(this._audioResourceRoot, audioPath);
      let anim = new AudioAnimTemplate(duration, relAudioPath);
      cachedAssetMap.set(node, anim);
      try {
        return this.jibo.animDB.AnimDBParser.parseAnimationFromAnim(anim);
      } catch (e) {
        return;
      }
    }
    return;
  }

  /**
   * Takes an InputTree and creates a Timeline composed of requested sound, animation and TTS
   *
   * @param {Node} inputTree Itemized timing data retrieved from TTS service
   * @param {SpeakOptions} options related to how the timeline should be constructed / expressed
   * @return {Promise<Timeline, Map<Node, TimeBounds>>} Timeline (before AutoRules) and WordSchedule
   */
  async _inputTreeToTimeline(inputTree: Node, options: SpeakOptions): Promise<[Timeline, Map<Node, TimeBounds>]> {

    // Resolve requested blocking anim and sound tags (for timing purposes)
    const blockingNodes = <any> inputTree.gatherDescendants( node => {
      return InputProcessor.isBlocking(node);
    }) as AssetNode[];

    blockingNodes.forEach( (node) => {
      let resolution = this._resolveAssetToPlayback(node);
      if (!resolution.resolved) {
        log.debug(`Could not find match for requested Asset  ${resolution.identifier}  because  ${resolution.reason}`);
      }
    });

    let wordScheduleRelevantNodes: Node[] = [];
    let nonBlockers: AssetNode[] = [];
    let noWords = true;

    inputTree.gatherDescendants().forEach( node => {
      if (InputProcessor.isUnboundedNonBlocking(node)) {
        nonBlockers.push(node as AssetNode);
      } else if (InputProcessor.isBlocking(node)) {
        const blockingNode = (node as AssetNode);
        if (blockingNode.playbackData) {
          const newBreak = TimelineManager._buildBreak(blockingNode.playbackData.playbackDuration / FRAME_RATE);
          wordScheduleRelevantNodes.push(newBreak);
          blockingNode.timeSyncNode = newBreak;
          nonBlockers.forEach( nBNode => nBNode.timeSyncNode = newBreak);
          nonBlockers = [];
        }
      } else {
        if (!InputProcessor.isAsset(node)) {
          if (!InputProcessor.isTimelessSSML(node)) {
            nonBlockers.forEach( nBNode => nBNode.timeSyncNode = node);
            nonBlockers = [];
          }
          wordScheduleRelevantNodes.push(node);

          // Check if any word nodes are present in the input (for later possible pruning)
          if (noWords && (node.type === NLPNodeType.WORD || InputProcessor.isSayAs(node))) {
            noWords = false;
          }
        }
      }
    });

    let dispatchOverride: DispatchType;
    if (options.followedByListen) {
      dispatchOverride = noWords ? DispatchType.ALL : DispatchType.TTS;
    }

    const fullSSMLText = InputProcessor.getSSMLTextFromArray(wordScheduleRelevantNodes);
    const shouldPrune = ((options.dispatchComplete === DispatchType.TTS) && (dispatchOverride !== DispatchType.ALL));
    const timingSSMLText = `<speak>${fullSSMLText}</speak>`;
    const speakingSSMLText = noWords ? null : timingSSMLText;
    const cached = timingSSMLText === speakingSSMLText;

    if (options.debugMode) {
      console.log(`TIMING:\n ${timingSSMLText}`);
      console.log(`SPEAKING:\n ${speakingSSMLText}`);
      console.log('-----------');
    }

    // TTS request parameters
    const params: TTSOptions = {
      locale: this.jibo.tts.TTSLocale.EN_US,
      voice: this.jibo.tts.TTSVoice.GRIFFIN,
      mode: this.jibo.tts.TTSMode.SSML,
      skipWordEvents: this.jibo.tts.TTSBoolean.TRUE,
      cached: cached ? this.jibo.tts.TTSBoolean.TRUE : this.jibo.tts.TTSBoolean.FALSE
    };

    const ttsSpeakData: TTSSpeakData = {
      timingSSMLText: timingSSMLText, // This is used to get timing of words
      speakingSSMLText: speakingSSMLText, //This is used by tts at the end
      params: params,
      dispatchOverride: dispatchOverride
    };

    const ttsTiming = await this.jibo.tts.getWordTimings(timingSSMLText, params);
    // Initialize the Master Timeline with the TTS layer
    let [timeline, mergedTokenTimes] = TimelineManager._initTimeline(ttsSpeakData, ttsTiming.tokentimes.tokens, options, shouldPrune);
    // Generate ttsWordSchedule with WordNodes
    const wordSchedule = TimelineManager._generateWordSchedule(wordScheduleRelevantNodes, mergedTokenTimes, options);
    // Add other layers (e.g. ANIM and SOUND) to the Master Timeline
    timeline = this._populateTimelineLayers(inputTree, timeline, wordSchedule);

    return [timeline, wordSchedule];
  }

  /**
   * Take in computed BREAK tag data and build an SSML node
   *
   * @param {number} size Length of the newly computed BREAK tag/node
   * @return {SSMLNode} SSML node that represents the break to be
   */
  static _buildBreak(size: number): SSMLNode {
    let newBreak = new SSMLNode(SSMLNodeType.BREAK);
    const roundedSize = Math.round(size * 1000) / 1000;
    newBreak.setAttribute('size', roundedSize);
    return newBreak;
  }

  /**
   * Attempt to find an asset given the provided Node (and optional TimeBounds) data
   *
   * @param {AssetNode} node Asset node that contains the information for resolving Asset
   * @param {number} [durationSeconds] Optional duration (in seconds) the asset must be contained within
   * @param {boolean} [randomizeOrient] Optional toggle to turn on the randomization of the resolved animation's orientation
   * @param {string} [cache] Optional cache to use other than the default
   * @return {AssetResolution} Object containing if the asset was resolved,
   * and identifying info if it wasn't
   */
  _resolveAssetToPlayback(node: AssetNode, durationSeconds?: number, randomizeOrient?: boolean, cache?: string): AssetResolution {

    const requestDescription = node.requestInfo.description;
    let resolution: AssetResolution = new AssetResolution();
    let identifier: string;
    let asset: Animation;
    let durationFramesToFill: number;  // Bounded duration
    let durationFramesLoopedPlayback: number;
    let durationFramesSinglePlayback: number;
    let playbackLoops: number = node.loops;

    if (durationSeconds !== undefined) {
      durationFramesToFill = durationSeconds * FRAME_RATE;  // Convert seconds to frames (assuming 30fps)
      if ((playbackLoops !== undefined) && (playbackLoops > 0)) {
        log.warn(`Requested invalid loops '${playbackLoops}' for time-bounded playback.`);
        playbackLoops = undefined;
      }
    }
    if (node.requestInfo.type === RequestType.NAME) {
      identifier = node.att.get('name') as string;
      if (identifier) {
        this.jibo.performance.log('EmbodiedSpeech_resolveAssetToPlayback_namedAnimationAsset', requestDescription);
        resolution.identifier = requestDescription;
        asset = this.jibo.animDB.getAnimByName(identifier);
      }
      if (!asset) {  // No asset found by that name
        resolution.reason = 'animation could not be found in the AnimationDB';
        return resolution;
      } else if (durationFramesToFill) {  // If we have an asset and a duration to fill
        if (playbackLoops === 0) {  // By looping, find optimal loop
          let choice: OptimalLoopResult;
          if (asset.meta.duration < durationFramesToFill) {
            choice = TimelineManager.findOptimalLoop([asset], durationFramesToFill);
          } else if (asset.durationRange.min < durationFramesToFill) {
            choice = TimelineManager.findOptimalLoop([asset], durationFramesToFill, true);
          } else {  // No asset could be looped in requested range
            resolution.reason = 'animation cannot fit in the requested time bounds';
            return resolution;
          }
          asset = choice.asset;
          durationFramesLoopedPlayback = choice.duration;
          playbackLoops = choice.loops;
        } else if (asset.durationRange.min <= durationFramesToFill) {  // By filling (often via HSF)
          durationFramesSinglePlayback = Math.max(asset.durationRange.min, Math.min(durationFramesToFill, asset.durationRange.max));
        } else {  // No asset found in requested range
          resolution.reason = 'animation cannot fit in the requested time bounds';
          return resolution;
        }
      }
    } else if (node.requestInfo.type === RequestType.QUERY) {
      this.jibo.performance.log('EmbodiedSpeech_resolveAssetToPlayback_queryAnimationAsset', requestDescription);
      const query: AnimQuery = {
         // Until we optimize the advanced AnimDB category searching
        categories: (node.categoryFilter.someOf.length > 0) ? node.categoryFilter.someOf : node.categoryFilter.allOf,
        includeMeta: node.metaFilter.allOf,
        includeSomeMeta: node.metaFilter.someOf,
        excludeMeta: node.metaFilter.noneOf,
      };
      const results: AnimResults = this.jibo.animDB.query(query);
      if (results.matching.length > 0) {
        if (durationFramesToFill) {  // If this is a time bounded request
          // If we're filling in a duration with animation loops, find the best match
          if (playbackLoops === 0) {  // If we're in auto-loop
            let choice: OptimalLoopResult;
            // First, try to find a loop match from animations using their default durations
            const loopableResults = results.matching.filter(result => {
              return result.meta.duration < durationFramesToFill;
            });
            if (loopableResults.length > 0) {
              choice = TimelineManager.findOptimalLoop(loopableResults, durationFramesToFill);
            } else {  // If we couldn't find a match from animations at default length, try them at their possibly sped up min duration
              const minResults = results.matching.filter(result => {
                return result.durationRange.min < durationFramesToFill;
              });
              if (minResults.length > 0) {
                choice = TimelineManager.findOptimalLoop(loopableResults, durationFramesToFill, true);
              }
            }
            if (choice) {
              asset = choice.asset;
              durationFramesLoopedPlayback = choice.duration;
              playbackLoops = choice.loops;
            }
          }
          // If we're filling it in with a single playback, find the best match
          // No need to check for loops more than 0, as they're not allowed in bounded
          else if (playbackLoops === undefined) {
            // Filter all results that contain the fill duration
            const goodFitResults = results.matching.filter(result => {
              return (result.durationRange.distanceFrom(durationFramesToFill) === 0);
            });
            // Choose the best result from there if one exists
            if (goodFitResults.length > 0) {
              asset = _.sample(goodFitResults);
              durationFramesSinglePlayback = durationFramesToFill;
            } else {  // If none found, filter again for sub-optimal matches and choose from them (if any)
              const validResults = results.matching.filter(result => {
                return (result.durationRange.min < durationFramesToFill);
              });
              if (validResults.length > 0) {
                // Here we find the animation with the highest durationRange.max which is under the desired duration
                // This could simply be an O(N) search for higherst durationRange.max
                validResults.sort((a, b) => {
                  return a.durationRange.max - b.durationRange.max;
                });
                asset = results.matching[0];
                durationFramesSinglePlayback = Math.min(durationFramesToFill, asset.durationRange.max);
              }
            }
          }
        } else {
          asset = _.sample(results.matching);
        }
      }
      if (!asset) {  // If there aren't any matches
        resolution.identifier = requestDescription;
        resolution.reason = 'no animation could be found in DB that matched requested attribute (i.e. CAT, META, DURATION) combination';
        return resolution;
      }
    } else if (node.requestInfo.type === RequestType.PATH) {
      identifier = node.att.get('path') as string;
      this.jibo.performance.log('EmbodiedSpeech_resolveAssetToPlayback_pathAnimationAsset', requestDescription);
      asset = this._pathAssets.get(node);
      if (!asset) {
        resolution.identifier = requestDescription;
        resolution.reason = 'requested path based asset could not be loaded';
        return resolution;
      }
    } else {
      resolution.identifier = requestDescription;
      resolution.reason = 'no animation could be found in DB (asset tag was malformed)';
      return resolution;
    }

    const [metaLayerPresence, muteConfig] = TimelineManager._createLayerPresences(asset, node);

    if (!cache) {
      cache = this.jibo.face.eye.CACHE_ID;
    }
    let animConfig: AnimConfig = {
      cache: cache
    };
    if (muteConfig) {
      animConfig.mutes = muteConfig;
    }

    const reqOrient = node.att.get('orientation') as string;
    if (reqOrient) {
      animConfig.orientation = this.jibo.animDB.Orientation[reqOrient];
    } else if (randomizeOrient) {
      animConfig.orientation = (Math.random() > AUTORULE_ORIENTATION_PROBABILITY) ? this.jibo.animDB.Orientation.LEFT : this.jibo.animDB.Orientation.RIGHT;
    }

    // Set the duration of either the animation at playback or duration we are going to be filling
    if (durationFramesToFill) {  // If we are bounded, use provided loop duration or default to fill bounded
      if (playbackLoops) {  // We can't have 0 here since that's been taken care of above
        animConfig.duration = durationFramesLoopedPlayback;
        animConfig.loops = playbackLoops;
      } else {
        animConfig.duration = durationFramesSinglePlayback;
      }
    } else {  // If we're not bounded, base duration computations off default
      if (playbackLoops) {
        durationFramesToFill = asset.meta.duration * playbackLoops;
        animConfig.loops = playbackLoops;
      } else {
        durationFramesToFill = asset.meta.duration;
      }
    }

    // Build the AnimDB Playback object and attach it to the asset node for later dispatch
    node.playbackData = {
      playbackGenerator: () => asset.createFromConfig(animConfig),
      playbackDuration: durationFramesToFill,
      playbackName: asset.name,
      playbackLayers: metaLayerPresence
    };
    resolution.resolved = true;
    resolution.identifier = identifier;

    return resolution;
  }

  /**
   * Finds the animation in a set of animation that fits into a given duration optimally
   *
   * @param {Animation[]} candidates = The set of animations that we are searching through
   * @param {number} durationFramesToFill - How much time we need to fill by looping
   * @param {boolean} [allowMin] - Whether or not to allow the min duration of the animation as an option
   * @return {OptimalLoopResult}}
   */
  static findOptimalLoop(candidates: Animation[], durationFramesToFill: number, allowMin=false): OptimalLoopResult {
    let optimalResult: OptimalLoopResult = {
      asset: undefined,
      duration: undefined,
      loops: undefined
    };
    let smallestError = Infinity;
    candidates.forEach(candidate => {
      const candidateDuration = allowMin ? candidate.durationRange.min : candidate.meta.duration;
      const loops = Math.floor(durationFramesToFill / candidateDuration);
      const remainder = durationFramesToFill % candidateDuration;
      const adjustment = Math.floor(remainder / loops);
      const optimalDuration = Math.min(candidateDuration + adjustment, candidate.durationRange.max);
      const error = durationFramesToFill - (optimalDuration * loops);
      if (error < smallestError) {
        smallestError = error;
        optimalResult.asset = candidate;
        optimalResult.duration = optimalDuration;
        optimalResult.loops = loops;
      }
    });
    return optimalResult;
  }

  /**
   * Generates both a MetaLayerPresence representations of the animations layers, taking into account the possible layer requests made in ESML
   * and a MuteConfig, to express to the AnimConfig how to play the animation
   *
   * @param {Animation} anim Animation
   * @param {AssetNode} node AssetNode
   * @return {Array<MetaLayerPresence, MuteConfig>}
   */
  static _createLayerPresences(anim: Animation, node: AssetNode): [MetaLayerPresence, MuteConfig] {

    const runtimeLayers = node.layers;
    const runtimeLayersToAdd = node.layersToAdd;

    let muteConfig: MuteConfig;

    let metaLayerPresence: MetaLayerPresence = {
      Body: false,
      Screen: false,
      Audio: false
    };

    if (anim.meta.layers.Body) {
      metaLayerPresence.Body = true;
    }
    if (anim.meta.layers.AudioEvent) {
      metaLayerPresence.Audio = true;
    }
    if (anim.meta.layers.Eye || anim.meta.layers.EyeTexture || anim.meta.layers.Overlay || anim.meta.layers.OverlayTexture || anim.meta.layers.Pixi || anim.meta.layers.BackgroundTexture) {
      metaLayerPresence.Screen = true;
    }

    // Override animation layers with requested layers
    if (runtimeLayers){

      muteConfig = {
        BODY: runtimeLayers.Body,
        SCREEN: runtimeLayers.Screen,
        AUDIO: runtimeLayers.Audio
      };

      // Override BODY
      if (runtimeLayers.Body !== undefined) {
        if (runtimeLayersToAdd.Body || ((runtimeLayers.Body && !metaLayerPresence.Body) || (!runtimeLayers.Body && metaLayerPresence.Body))) {
          metaLayerPresence.Body = runtimeLayers.Body;
        }
      }

      // Override AUDIO
      if(runtimeLayers.Audio !== undefined) {
        if (runtimeLayersToAdd.Audio || ((runtimeLayers.Audio && !metaLayerPresence.Audio) || (!runtimeLayers.Audio && metaLayerPresence.Audio))) {
          metaLayerPresence.Audio = runtimeLayers.Audio;
        }
      }

      // Override SCREEN
      if(runtimeLayers.Screen !== undefined) {
        if (runtimeLayersToAdd.Screen || ((runtimeLayers.Screen && !metaLayerPresence.Screen) || (!runtimeLayers.Screen && metaLayerPresence.Screen))) {
          metaLayerPresence.Screen = runtimeLayers.Screen;
        }
      }
    }

    return [metaLayerPresence, muteConfig];
  }

  /**
   * Generates the initial timeline composed of TTS timing data
   *
   * @param {TTSSpeakData} ttsSpeakData Data containing all string to speak and speaking options
   * @param {TTSTokenWord[]} tokenTimes TTS Token timings
   * @param {SpeakOptions} options related to how the timeline should be constructed / expressed
   * @param {boolean} [shouldPrune=false] If the TTS.speak call should be ended early
   * @return {Array<Timeline, TTSTokenWord[]>} Initialized Timeline and updated TTS Token timings
   */
  static _initTimeline(ttsSpeakData: TTSSpeakData, tokenTimes: TTSTokenWord[], options: SpeakOptions, shouldPrune=false): [Timeline, TTSTokenWord[]] {

    let timeline: Timeline = new Timeline(options.frameBuffer, options.assetRelativeEnd, options.enableLayerMerging);

    // Get the beginning and end of the entire utterance
    const start = tokenTimes[0].start;
    let stop = tokenTimes[tokenTimes.length - 1].end;

    if (shouldPrune) {
      stop = this.getPrunedStopTime(tokenTimes);
      ttsSpeakData.params.earlyStopTime = stop;
    }

    const ttsFrame: TTSFrame = {
      start: start,
      stop: stop,
      data: ttsSpeakData
    };

    timeline._init([ttsFrame]);

    return [timeline, tokenTimes];
  }

  /**
   * Get the pruned version of the end time of a TTS text.
   *
   * @param {TTSTokenWord[]} tokenTimes TTS Token timings
   */
  static getPrunedStopTime(tokenTimes: TTSTokenWord[]): number {
    // We expect a long pause [lpau] may or may not be added to the end.
    // If there is one, we will keep the time of the pause.
    let idx;
    let pauseTime = 0;
    for (idx = tokenTimes.length - 1; idx >= 0; idx--) {
      if (tokenTimes[idx].name === TTS_BREAK) {
        continue;
      } else if ((idx === tokenTimes.length - 1) && (tokenTimes[idx].name === TTS_PAU)) {
        pauseTime = (tokenTimes[idx].end - tokenTimes[idx].start);
      } else {
        break;
      }
    }
    if (idx < 0) {
      return tokenTimes[0].start + pauseTime;
    }
    return tokenTimes[idx].end + pauseTime;
  }

  /**
   * Takes in list of Word Nodes and TTS Token timings and merges them into one structure
   *
   * @param {Node[]} wordNodes Word nodes extracted from the InputTree
   * @param {TTSTokenWord[]} tokenTimes TTS Token timings
   * @param {SpeakOptions} options related to how the timeline should be constructed / expressed
   * @return {Map<Node, TimeBounds>} Start and stop time of each WordNode
   */
  static _generateWordSchedule(wordNodes: Node[], tokenTimes: TTSTokenWord[], options: SpeakOptions): Map<Node, TimeBounds> {

    if (options.debugMode) {
      console.log('Word timing report (with buffer):');
      console.log('--------------------------------');
    }

    let ttsWordSchedule = new Map<Node, TimeBounds>();
    let lastNodeIdx = 0;
    for (let i = 0; i < tokenTimes.length; i++) {  // For each token

      let wordNodeFound = false;
      const token = tokenTimes[i];

      const tokenTime = {
        start: token.start,
        stop: token.end
      };

      for (let j = lastNodeIdx; j < wordNodes.length; j++) {  // Find the corresponding WordNode

        const word = wordNodes[j];
        if (token.name === TTS_BREAK || token.name === TTS_SAY_AS || token.name === TTS_AUDIO_BREAK) {
          if (((token.name === TTS_BREAK) && (word.type === SSMLNodeType.BREAK)) ||
              ((token.name === TTS_AUDIO_BREAK) && (word.type === SSMLNodeType.AUDIO_BREAK)) ||
              ((token.name === TTS_SAY_AS) && (word.type === SSMLNodeType.SAY_AS)))
          {
            ttsWordSchedule.set(word, tokenTime);
            lastNodeIdx = ++j;
            wordNodeFound = true;

            if (options.debugMode){
              console.log(`${token.name}: ${token.start.toFixed(3)} - ${token.end.toFixed(3)}  (${(token.end - token.start).toFixed(3)})`);
            }
            break;
          }
        } else if (word.value && (token.name.toLowerCase() === word.value.toLowerCase())) {
          ttsWordSchedule.set(word, tokenTime);

          if (options.debugMode){
            console.log(`${word.value}: ${token.start.toFixed(3)} - ${token.end.toFixed(3)}  (${(token.end - token.start).toFixed(3)})`);
          }

          lastNodeIdx = ++j;
          wordNodeFound = true;
          break;
        }
      }
      if ((token.name !== TTS_PAU) && (!wordNodeFound)) {
        if (options.debugMode) {
          console.log(`Unable to align TTS token:  ${token.name}  with requested words`);
        }
      }
    }

    if (options.debugMode) {
      console.log('-------------------');
    }
    return ttsWordSchedule;
  }

  /**
   * Takes an InputTree and populates layers (e.g. Animation and Sound) of supplied Timeline
   *
   * @param {Node} inputTree InputTree containing all input information
   * @param {Timeline} timeline In-progress Timeline with only TTS layer
   * @param {Map<Node, TimeBounds>} wordSchedule holds the time bounds for each word node
   * @return {Timeline} Timeline with non-TTS layers merged into it
   */
  _populateTimelineLayers(inputTree: Node, timeline: Timeline, wordSchedule: Map<Node, TimeBounds>): Timeline {

    // Gather up all AssetNodes from the inputTree
    let assetNodes: AssetNode[] = inputTree.gatherDescendantsType(AssetNodeType.ES) as AssetNode[];
    assetNodes = assetNodes.concat(inputTree.gatherDescendantsType(AssetNodeType.AUDIO) as AssetNode[]);

    // Make sure we insert all requested blocking assets first, then unbounded, then bounded assets
    let blockingAssetNodes = assetNodes.filter( (node) => InputProcessor.isBlocking(node));
    let emptyAssetNodes = blockingAssetNodes.concat(
      assetNodes.filter( (node) => (InputProcessor.isEmpty(node) && !InputProcessor.isBlocking(node))));
    let prioritizedAssetNodes = emptyAssetNodes.concat(
      assetNodes.filter( (node) => !InputProcessor.isEmpty(node)));

    log.debug('ESML resolution report:');
    log.debug('-----------------------');

    // Get the timing boundaries for each and attempt to insert it in the ANIM layer
    prioritizedAssetNodes.forEach( (node) => {
      let bounds: TimeBounds;
      let blocking: boolean = false;
      if (InputProcessor.isBlocking(node)) {  // Blocking asset
        blocking = true;
        if ((node.playbackData) && (wordSchedule.has(node.timeSyncNode))) {
          const timeSyncNode = node.timeSyncNode as SSMLNode;
          bounds = Object.assign({}, wordSchedule.get(timeSyncNode));
        } else {
          log.debug(`Could not resolve time-sync information for blocking asset request: ${node.requestInfo.description}`);
          return;
        }
      } else {  // Non-blocking asset
        let resolution: AssetResolution;
        if (InputProcessor.isEmpty(node)) {
          if (wordSchedule.has(node.timeSyncNode)) {
            let timeSyncNode = node.timeSyncNode as SSMLNode;
            bounds = Object.assign({}, wordSchedule.get(timeSyncNode));
          } else {
            log.debug(`Could not resolve time-sync information for non-blocking asset request:  ${node.requestInfo.description}`);
            return;
          }
          resolution = this._resolveAssetToPlayback(node);
        } else {
          try {
            bounds = TimelineManager._getBoundariesFromChildren(node, wordSchedule);
          } catch (e) {
            log.warn(e);
            return;
          }
          resolution = this._resolveAssetToPlayback(node, (bounds.stop - bounds.start));
        }
        if (!resolution.resolved) {
          log.debug(`Could not find match for requested Asset  ${resolution.identifier}  because  ${resolution.reason}`);
          return;
        }
      }
      const dynamicStopBoundary = bounds.start + (node.playbackData.playbackDuration / FRAME_RATE);
      const inserted = timeline.anim.insert(new TimelineFrame(bounds.start, dynamicStopBoundary, node, blocking));

      if (inserted) {
        node.playbackData.playbackPr = node.playbackData.playbackGenerator();
        // TODO: Make this based on the Meta terms at some point
        if (node.playbackData.playbackName.toLowerCase().indexOf('emoji') !== -1) {
          log.info(`Emoji  ${node.playbackData.playbackName}  triggered via  ESML`);
          this.emojiCapReached = true;
        }
        log.debug(`Inserted asset  ${node.playbackData.playbackName}  in Timeline @  ${bounds.start.toFixed(3)} - ${dynamicStopBoundary.toFixed(3)}`);
        if(node.playbackData.playbackName.includes('SSA')){
           this.jibo.performance.log('EmbodiedSpeech_ESML_ToBeDispatchedSSA', node.playbackData.playbackName);
        }
        else{
           this.jibo.performance.log('EmbodiedSpeech_ESML_ToBeDispatchedAnim', node.playbackData.playbackName);
        }
      } else {
        log.debug(`Could not insert asset  ${node.playbackData.playbackName}  in Timeline because it conflicts with other content @  ${bounds.start.toFixed(3)} - ${dynamicStopBoundary.toFixed(3)}`);
      }
    });

    log.debug('-----------------------');
    return timeline;
  }

  /**
   * Takes in AutoTagTrees and creates a prioritized map of TimelinesFrames
   *
   * @param {Node[]} autoTagTrees which contain which auto-rules match what word nodes
   * @param {Map<Node, TimeBounds>} wordSchedule holds the time bounds for each word node
   * @param {Timeline} timeline In-progress Master Timeline
   * @return {Map<number, AutoRuleMatch[][]>} Priority map of timeline frames generated by auto-rules
   */
  _autoTagTreesToPrioritizedTimelines(autoTagTrees: Node[],
                                      wordSchedule: Map<Node, TimeBounds>,
                                      timeline: Timeline): Map<number, AutoRuleMatch[][]> {

    let priorityMap = new Map<number, AutoRuleMatch[][]>();

    // Gather all the timing boundaries for AutoRule Trees
    autoTagTrees.forEach( ruleTree => {
      let cache: string;
      const autoRule = ruleTree.getAttribute('autoRule') as string;
      switch (autoRule) {
        case AutoRuleNames.Question:
        case AutoRuleNames.Comma:
        case AutoRuleNames.Initiate:
        case AutoRuleNames.Blink:
        case AutoRuleNames.DoubleBlink:
        case AutoRuleNames.BeatBlink:
          cache = CacheUtils.GlobalCacheName;
          break;
        case AutoRuleNames.HotWords:
        default:
          cache = this.jibo.face.eye.CACHE_ID;
          break;
      }

      // If the autoRule matched the tree, get the bounds for each match
      if (ruleTree.children.length > 0) {
        const priority = ruleTree.getAttribute('priority') as number;
        let ruleFrames: AutoRuleMatch[] = [];

        // For each time the autoRule matches the tree, try to add its associated assets to the timelines
        ruleTree.forEachChild( (subTree: AssetNode) => {
          let bounds: TimeBounds;
          let resolution: AssetResolution;
          if (InputProcessor.isEmpty(subTree) || InputProcessor.isExplicitlyNonBlocking(subTree)) {
            if (!wordSchedule.has(subTree.timeSyncNode)) {
              return;
            }
            const timeSyncNode = subTree.timeSyncNode as SSMLNode;
            bounds = Object.assign({}, wordSchedule.get(timeSyncNode));
            const position = subTree.getAttribute('position');
            bounds.start = (position === 'after') ? bounds.stop : bounds.start;
            resolution = this._resolveAssetToPlayback(subTree, undefined, true, cache);
          } else {
            try {
              bounds = TimelineManager._getBoundariesFromChildren(subTree, wordSchedule);
            } catch (e) {
              log.warn(e);
              return;
            }
            resolution = this._resolveAssetToPlayback(subTree, (bounds.stop - bounds.start), true, cache);
            if (!resolution.resolved && (Math.random() < AUTORULE_GATE_RATE)) {
              resolution = this._resolveAssetToPlayback(subTree, undefined, true, cache);  // Try to insert it unbounded instead
            }
          }
          if (!resolution.resolved) {
            log.debug(`Could not find match for AutoRule  ${resolution.identifier}  because  ${resolution.reason}`);
            return;
          }
          const dynamicStopBoundary = bounds.start + (subTree.playbackData.playbackDuration / FRAME_RATE);
          ruleFrames.push({
            layer: timeline.anim,
            frame: new TimelineFrame(bounds.start, dynamicStopBoundary, subTree)
          });
        });

        // Update the prioritized map of matches with all matches from current autoRule
        if (ruleFrames.length > 0) {
          let currMatches: AutoRuleMatch[][] = priorityMap.get(priority);
          if (!currMatches) {
            priorityMap.set(priority, currMatches = []);
          }
          currMatches.push(ruleFrames);
        }
      }
    });

    return priorityMap;
  }

  /**
   * Finds the first and last children word(s) nodes of the supplied node for Timing
   *
   * @param {Node} node parent of the children being gathered
   * @param {Map<Node, TimeBounds>} wordSchedule holds the time bounds for each word node
   * @return {TimeBounds} start/stop time of the first/last child nodes
   */
  static _getBoundariesFromChildren(node, wordSchedule): TimeBounds {
    let firstWordBounds: TimeBounds;
    let lastWordBounds: TimeBounds;

    // Find the first and last WordNode child of the current node for timing bounds
    node.forEachChild( child => {
      let wordBounds = wordSchedule.get(child);  // Check if we have the time bounds for the child
      if (!wordBounds && (InputProcessor.isAsset(child) || InputProcessor.isBreak(child))) {  // If we don't have the timing of the child directly
        wordBounds = wordSchedule.get((child as AssetNode).timeSyncNode);  // Check if the child has a time sync node
      } else if (!InputProcessor.isEmpty(child)) {
        wordBounds = TimelineManager._getBoundariesFromChildren(child, wordSchedule);
      }

      if (wordBounds) {
        if (!firstWordBounds) {
          firstWordBounds = wordBounds;
        } else {
          lastWordBounds = wordBounds;
        }
      }
    });

    // Node only had one child, use that for lastWord too
    if (firstWordBounds) {
      lastWordBounds = lastWordBounds || firstWordBounds;
    } else {
      throw new Error('Unable to find timing bounds for word length based Animation.');
    }

    const timeBounds: TimeBounds = {
      start: firstWordBounds.start,
      stop: lastWordBounds.stop
    };

    return timeBounds;
  }

  /**
   * Takes a prioritized Map of TimelineFrames to be merged with supplied (Master) Timeline
   *
   * @param {Map<number, AutoRuleMatch[][]>} pending: auto-rule generated assets
   * @param {Timeline} timeline In-progress master Timeline
   * @return {Timeline} Completed timeline
   */
  _mergePendingWithMaster(pending: Map<number, AutoRuleMatch[][]>, timeline: Timeline): Timeline {
    // Get all priorities as a flattened list
    let priorities = [];
    pending.forEach( (_val, key) => priorities.push(key) );
    priorities.sort();

    log.debug('AutoRules resolution report:');
    log.debug('---------------------------------------');

    // By priority, try to insert all autoRule matches into the Timeline
    priorities.forEach( priority => {
      _.shuffle(pending.get(priority)).forEach((autoRule) => {  // Shuffle for a better experience :)
        (autoRule as AutoRuleMatch[]).forEach((ruleMatch) => {

          const isEmoji = (ruleMatch.frame.data.playbackData.playbackName.toLowerCase().indexOf('emoji') !== -1);
          if (isEmoji && this.emojiCapReached) {
            log.debug(`Could not insert AutoRule  ${ruleMatch.frame.data.getAttribute('rule')}:${ruleMatch.frame.data.playbackData.playbackName}  in Timeline because only 1 Emoji is allowed per input`);
            return;
          }

          const inserted = ruleMatch.layer.insert(ruleMatch.frame, true);
          if (inserted) {
            ruleMatch.frame.data.playbackData.playbackPr = ruleMatch.frame.data.playbackData.playbackGenerator();
            if (isEmoji) {
              log.info(`Emoji  ${ruleMatch.frame.data.playbackData.playbackName}  triggered via  AutoRule`);
              this.emojiCapReached = true;
            }
            log.debug(`AutoRule  ${ruleMatch.frame.data.getAttribute('rule')}:${ruleMatch.frame.data.playbackData.playbackName}  inserted @  ${ruleMatch.frame.start.toFixed(3)} - ${ruleMatch.frame.stop.toFixed(3)}`);
            this.jibo.performance.log('EmbodiedSpeech_AutoRule_ToBeDispatchedAnim', ruleMatch.frame.data.playbackData.playbackName);
          } else {
            log.debug(`Could not insert AutoRule  ${ruleMatch.frame.data.getAttribute('rule')}:${ruleMatch.frame.data.playbackData.playbackName}  in Timeline because it conflicts with other content @  ${ruleMatch.frame.start.toFixed(3)} - ${ruleMatch.frame.stop.toFixed(3)}`);
          }
        });
      });
    });

    log.debug('---------------------------------------');
    return timeline;
  }

}
