const findRoot = require('find-root');

const ROOT = findRoot(__filename);
const SOUNDS_ROOT = ROOT + '/resources/audio/';

export const Anims = {
  ENGAGE: `User_Speak_Begin_01`,
  DISENGAGE: `User_Speak_End_01`,
  THINKING: `Thinking_Short_01`,
  BLINK: `Eye_Quick_Blink_01`,
  HEAD_BOB: [
    `Listen_Head_Bob_01`,
    `Speak_Posture_Shift_01`,
  ],
};

export enum EyeTransitionStyle { POP, BLINK }
export enum EyeTransitionDirection { TO, FROM }


export class AnimSelector {

  /**
   * Builds a perceptual eye transition animation name
   * @param {boolean} seePerson
   * @param {EyeTransitionStyle} style
   * @param {EyeTransitionDirection} direction
   * @param {boolean} [sound=true]
   * @return {string}
   */
  static getPerceptualEyeTransition(seePerson: boolean, style: EyeTransitionStyle, direction: EyeTransitionDirection, sound=true): string {
    let nameComps = [];
    nameComps.push(seePerson ? 'hj-sp-transition-' : 'hj-dsp-transition-');
    nameComps.push(direction === EyeTransitionDirection.FROM ? 'from-' : 'to-');
    nameComps.push(style === EyeTransitionStyle.POP ? 'pop' : 'blink');
    if (direction === EyeTransitionDirection.TO) {
      nameComps.push(sound ? '' : '-ns');
    }
    return nameComps.join('');
  }

  /**
   * Builds a perceptual eye pose animation name
   * @param {boolean} seePerson
   * @param {boolean} listening
   * @return {string}
   */
  static getPerceptualEyePose(seePerson: boolean, listening: boolean): string {
    let nameComps = [];
    nameComps.push(listening ? 'l-' : 'nl-');
    nameComps.push(seePerson ? 'sp' : 'dsp');
    return nameComps.join('');
  }

}

