import {EmbodiedListen} from './EmbodiedListen';
import {CacheUtils} from 'jibo-cai-utils';

// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../../jibo');
export type AnimConfig = JiboImport.animDB.AnimConfig;
export type PlaybackOptions = JiboImport.animDB.PlaybackOptions;
export type PlaybackResult = JiboImport.animDB.PlaybackResult;
// ------------------------------------------------
import { AnimationOptions } from './Types';

export const WIN_NAME = 'Embodied Listen';
let ALL_MINUS_BASE: any;


export class Utils {

  /**
   * Play animation
   * @param {AnimationOptions} options Animation playback and configuration options
   * @return {PlaybackResult}
   */
  static playAnimation(options: AnimationOptions): PlaybackResult {
    const jibo = options.jibo;
    if (!ALL_MINUS_BASE) {
      ALL_MINUS_BASE = jibo.expression.dofs.ALL.minus(jibo.expression.dofs.BASE);
    }
    const asset = jibo.animDB.getAnimByName(options.animName);
    if (!asset) {
       throw new Error(`No animation of name '${options.animName}' found in animDB`);
    }

    const hasDOFs = !!(options.config && options.config.dofs);
    const config: AnimConfig = hasDOFs ? options.config : Object.assign(options.config || { cache: CacheUtils.GlobalCacheName }, {
      dofs: ALL_MINUS_BASE
    });
    const hasOwner = !!(options.options && options.options.ownerInformation);
    const playbackOptions: PlaybackOptions = hasOwner ? options.options : Object.assign(options.options || {}, {
      ownerInformation: EmbodiedListen.NONHJ_OWNER_INFORMATION,
    });

     return asset.play(config, playbackOptions);
  }

  /**
   * Set color of LED ring
   * @param {jibo} jibo The jibo object.
   * @param {Array.<number>} color The RGB LED color.
   */
  static setLED(jibo: typeof JiboImport, color: number[]): void {
    jibo.performance.log('EmbodiedListenSettingLEDSkill', (color[0] !== 0)  ? 'ON' : 'OFF');
    jibo.expression.setLEDColor(color as [number, number, number]);
  }

  /**
   * Play sound
   * @param {jibo} jibo The jibo object.
   * @param {string} path The path to the sound file
   * @return {Promise}
   */
  static playSound(jibo: typeof JiboImport, path: string): Promise<any> {
    return new Promise( (resolve, reject) => {
      jibo.performance.log('EmbodiedListenLoadSoundSkill');
      const sound = jibo.loader.cached(path, CacheUtils.GlobalCacheName);
      if (sound) {
        jibo.performance.log('EmbodiedListenPlaySoundSkill', path);
        sound.play( () => resolve() );
      }
      else {
        // Load the file first
        jibo.loader.load({
          type: 'sound',
          id: path,
          cache: CacheUtils.GlobalCacheName,
          src: path,
          complete: (err:Error, sound) => {
            if (err) {
              return reject(err);
            }
            jibo.performance.log('EmbodiedListenPlaySoundSkill', path);
            sound.play( () => resolve() );
          }
        });
      }
    });
  }

  /**
   * Packs three individual rgb values into one 32 bit integer
   * @param {number[]} rbgArray Array of [r,g,b] values (where each value is in range 0-255)
   * @returns {number}
   */
  static packRGB(rbgArray: number[]): number {
    return (rbgArray[0] & 0xff) << 16 |
      (rbgArray[1] & 0xff) << 8 |
      (rbgArray[2] & 0xff);
  }

  /**
   * Unpacks a 32 bit representation of an rgb value into three r g b values
   * @param {number} rgbPacked a packed representation
   * @returns {number[]}
   */
  static unpackRGB(rgbPacked: number): number[] {
    const r = (rgbPacked >>> 16) & 0xff;
    const g = (rgbPacked >>> 8) & 0xff;
    const b = (rgbPacked) & 0xff;

    return [r, g, b];
  }
}
