// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../../jibo');
export type Animation = JiboImport.animDB.Animation;
export type AnimQuery = JiboImport.animDB.AnimQuery;
// ------------------------------------------------

import {Log} from 'jibo-log';

export class Utils {

  /**
   * Converts a number in seconds to milliseconds
   *
   * @param {number} seconds in seconds
   * @return {number} timespan in milliseconds
   */
  static secToMillisec(seconds: number): number {
    return seconds * 1000;
  }

  /**
   * Converts a number in milliseconds to seconds
   *
   * @param {number} seconds in milliseconds
   * @return {number} timespan in seconds
   */
  static millisecToSec(milliseconds: number): number {
    return milliseconds / 1000;
  }

  /**
   * Load animation(s) into cache
   *
   * @param {jibo} jibo Jibo runtime instance
   * @param {string|AnimQuery} query Name of animation or AnimQuery
   * @param {string} cacheName Name of cache to load animation into
   * @return {Promise} The promise resolved when animation(s) have been cached
   */
  static async loadAnimationIntoCache(jibo: typeof JiboImport, query: string|AnimQuery, cacheName: string): Promise<any> {
    let assets: Animation[] = [];
    if (typeof query === 'string') {
      const asset = jibo.animDB.getAnimByName(query);
      if (!asset) {
        return Promise.reject(`No animation of name  '${query}'  found in animDB`);
      } else {
        assets.push(asset);
      }
    } else {
      const results = jibo.animDB.query(query);
      if (!results.matching.length) {
        return Promise.reject(`No animation of  ${query}  found in animDB`);
      } else {
        assets.push(...results.matching);
      }
    }
    assets.forEach(async asset => {
      await asset.createFromConfig({
        cache: cacheName
      });
    });
  }

}

export class ExtPromise<T> {

  resolve: (d?: T) => any;
  reject: (err?: any) => any;
  promise: Promise<T>;

  constructor() {
    this.promise = new Promise<T>((res, rej) => {
      this.resolve = res;
      this.reject = rej;
    });
  }
}

export interface TimeoutOptions<T> {
  log?: Log;
  logMessage?: string;
  timeoutValue?: T;
}

export function timeout<T>(pr: Promise<T>, timeoutTimeMs: number, options: TimeoutOptions<T> = {}): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    let timeout = setTimeout(() => {
      if (options.log) {
        let msg = `Timeout of ${timeoutTimeMs} ms occurred`;
        if (options.logMessage) {
          msg += `. ${options.logMessage}`;
        }
        options.log.warn(msg);
      }
      resolve(options.timeoutValue);
    }, timeoutTimeMs);

    pr.then((data) => {
      clearTimeout(timeout);
      resolve(data);
    }).catch(e => {
      clearTimeout(timeout);
      reject(e);
    });
  });
}
