import { Event, EventContainer } from 'jibo-typed-events';


export class IncomingEvents extends EventContainer {
  hjHeard = new Event('Hey Jibo heard');
  startListen = new Event('Started listening');
  oriented = new Event('Oriented');
  sos = new Event('Start of speech');
  cloudFinished = new Event('Cloud finished');
  eos = new Event('End of speech');
  //interrupted = new Event('Listen Interrupt');

  personFound = new Event('Person visually found');
  personLost = new Event('Person visually lost');

  constructor() {
    super();
  }
}

export class OutgoingEvents extends EventContainer {
  finished = new Event('Embodied Listen finished');

  constructor() {
    super();
  }
}

export class InternalEvents extends EventContainer {
  reset = new Event(`Reset`);
  enterActiveMode = new Event(`Enter Active Mode`);
  exitActiveMode = new Event(`Exit Active Mode`);

  constructor() {
    super();
  }
}
