import Node from 'jibo-node-xml';
import { NodeType } from 'jibo-node-xml';
import { NLPNodeType, SentenceType, WordType } from '../../common/Types';
import { PathUtils } from 'jibo-cai-utils';
import { Lexer } from './Lexer';

let stemmer: any = require('stemmer');
let root = PathUtils.getProjectRoot(__filename);
let common_words = require(root + '/resources/common_words_stemmed_500.json');


export interface DialogContext {
  existing: Set<string>;
}

export class PartNode extends Node {
  tags = [];

  constructor(value?: string) {
    super(NLPNodeType.PART, value);
  }
}


export class SentenceNode extends Node {
  words: string[] = [];

  set sentenceType(type: string) {
    this.setAttribute('sentenceType', type);
  }

  get sentenceType() {
    return (this.getAttribute('sentenceType') as string);
  }

  constructor(value?: string) {
    super(NLPNodeType.SENTENCE, value);
    this.sentenceType = SentenceType.REGULAR as string;
  }
}


export class WordNode extends Node {

  public contractionBase: WordNode;

  set wordType(type: string) {
    this.setAttribute('wordType', type);
  }

  get wordType() {
    return (this.getAttribute('wordType') as string);
  }

  constructor(value?: string) {
    super(NLPNodeType.WORD, value);
  }
}

export type Tag = [string, string];
export type POSTags = {
    tokentags: Tag[] // e.g., [["WORD", "NN"]]
};

export class Tagger {
  constructor(private jibo) {
    this.jibo = jibo;
  }

  public async tag(words: string[]): Promise<Tag[]> {
    let data: POSTags = await this.jibo.tts.getPOSTags(words);
    return data.tokentags;
  }
}

export class NLParser {

  lexer: Lexer;
  neverNew = new Set();
  globalInd = 0;
  dialogContext: DialogContext;
  contractions: string[];
  expansions: string[];
  contractionBase: WordNode = null;
  wordCounts = new Map<string, number>();
  private tagger: Tagger;

  constructor(jibo) {
    this.lexer = new Lexer(jibo);
    this.tagger = new Tagger(jibo);
    common_words
      .map(w => stemmer(w))
      .forEach(w => this.neverNew.add(w));
  }

  _parseWord(word, pos) {
    let textNode = new WordNode(word);
    textNode.setAttribute('globalInd', this.globalInd++);
    textNode.setAttribute('stem', stemmer(word));
    textNode.setAttribute('pos', pos);

    if (this.expansions && this.contractions) {
      let wordCount = this.wordCounts.get(word);
      if (wordCount !== undefined) {
        wordCount++;
      } else {
        wordCount = 0;
      }
      this.wordCounts.set(word, wordCount);
      let foundIndexes = this.expansions.reduce((arr, elm, idx) => {
        if (elm === word) {
          arr.push(idx);
        }
        return arr;
      }, []);
      if (foundIndexes.length > 0) {
        let contractedForm = this.contractions[foundIndexes[wordCount]];
        if (contractedForm !== word) {
          if (contractedForm !== '') {
            textNode.setAttribute('contraction', contractedForm);
            this.contractionBase = textNode;
          } else {
            if (this.contractionBase) {
              textNode.contractionBase = this.contractionBase;
            } else {
              throw new Error('Cannot find base word of expanded contraction');
            }
          }
        }
      } else {
        throw new Error('Error when attempting to expand contractions.');
      }
    }

    if (pos.startsWith('VB')) {
      textNode.wordType = WordType.VERB as string;
    }
    else if (pos.startsWith('N')) {
      textNode.wordType = WordType.NOUN as string;
    }
    else if (pos.startsWith('P')) {
      textNode.wordType = WordType.PREP as string;
    }
    else if (word[0] === ',' ||
      pos.startsWith('CC')) {
      textNode.wordType = WordType.CONN as string;
    }
    else {
      textNode.wordType = WordType.UNKN as string;
    }

    // Detect new words
    let stemmed = textNode.getAttribute('stem') as string;
    if (!this.neverNew.has(stemmed) && !this.dialogContext.existing.has(stemmed)) {
      this.dialogContext.existing.add(stemmed);
      textNode.setAttribute('new', true);
    }

    return textNode;
  }

  _createWordNodes(tags: Tag[]): WordNode[] {
    return tags.map(tag => {
      const pos = tag[1];
      const word = tag[0];
      return this._parseWord(word, pos);
    });
  }

  setDialogContext(dialogContext: DialogContext) {
    this.dialogContext = dialogContext;
  }

  /**
   * @param {string|string[]} input Text string to generatePreInputTree into tree.
   * @param {string[]} expansions
   * @param {string[]} contractions
   * @return {Node}
   */
  async parse(input: string|string[], expansions?: string[], contractions?: string[]): Promise<Node> {
    if (typeof input === 'string') {
      input = await this.lexer.lex(input);
    }
    return this._parse(input, expansions, contractions);
  }

  /**
   * @param {string[]} words words to generatePreInputTree into tree.
   * @param {string[]} expansions
   * @param {string[]} contractions
   * @return {Node}
   */
  private async _parse(words: string[], expansions?: string[], contractions?: string[]): Promise<Node> {
    this.globalInd = 0;
    this.wordCounts = new Map<string, number>();
    this.expansions = null;
    this.contractions = null;

    if (!this.dialogContext) {
      this.dialogContext = {
        existing: new Set<string>()
      };
    }

    if (expansions && contractions) {
      this.expansions = expansions;
      this.contractions = contractions;
    }

    let root = new Node(NodeType.ROOT);
    root.setAttribute('treeType', 'NLP_TREE');
    let sentence = new SentenceNode();
    root.addChild(sentence);

    words.forEach(w => {
      if (w === '.' || w === '?' || w === '!' || w === ';' || w === ':') {
        if (w === '?') {
          sentence.sentenceType = SentenceType.QUESTION;
        } else if (w === '!') {
          sentence.sentenceType = SentenceType.EXCLAMATION;
        }

        let endNode = new WordNode(w);
        endNode.wordType = WordType.END;
        root.addChild(endNode);
        sentence = new SentenceNode();
        sentence.words = [];
        sentence.sentenceType = SentenceType.REGULAR;
        root.addChild(sentence);
      }
      else {
        sentence.words.push(w);
      }
    });
    let lastSentence = <any> root.children[root.children.length - 1] as SentenceNode;
    if (lastSentence.type === NLPNodeType.SENTENCE && !lastSentence.words.length) {
      root.removeChild(lastSentence);
    }

    // Now we go through every sentence and split it into parts (by connecting words)
    const sentences = root.gatherChildrenType(NLPNodeType.SENTENCE) as SentenceNode[];
    for (let sentence of sentences) {
      sentence.value = sentence.words.join(' ');
      let tags: Tag[];
      try {
        tags = await this.tagger.tag(sentence.words);
      } catch (err) {
        throw new Error('Error when attempting to retreive POS tags');
      }
      sentence.words = null;
      let part = new PartNode();
      part.setAttribute('verbCount', 0);
      sentence.addChild(part);
      tags.forEach(tag => {
        let word = tag[0];
        let pos = tag[1];
        if (word === ',' || pos.startsWith('CC')) {
          let endNode = new WordNode(word);
          endNode.wordType = WordType.CONN as string;
          endNode.setAttribute('pos', pos);
          sentence.addChild(endNode);
          part = new PartNode();
          part.setAttribute('verbCount', 0);
          sentence.addChild(part);
        }
        else {
          if (pos.startsWith('V')) {
            part.modifyAttribute('verbCount', (oldVal: number) => oldVal + 1);
          }
          part.tags.push(tag);
        }
      });

      // Delete all empty parts
      sentence.gatherChildrenType(NLPNodeType.PART, (p: PartNode) => !p.tags.length)
        .forEach(p => {
          sentence.removeChild(p);
        });

      // Now we take every sentence and and chunk it
      sentence.setAttribute('verbCount', 0);
      const parts = sentence.gatherChildrenType(NLPNodeType.PART) as PartNode[];
      parts.forEach(part => {
        const pvc = part.getAttribute('verbCount') as number;
        sentence.modifyAttribute('verbCount', (svc: number) => svc + pvc);
        part.value = part.tags.map(t => t[0]).join(' ');
        this._createWordNodes(part.tags)
          .forEach(w => part.addChild(w));
      });
    }

    // Delete all empty sentences
    root.gatherChildrenType(NLPNodeType.SENTENCE, p => !p.children.length)
      .forEach(p => root.removeChild(p));

    return root;
  }
}
