import Node from 'jibo-node-xml';
import { AutoRule } from './AutoRule';
import { NLPNodeType, AssetNodeType } from '../../common/Types';
import { TRPart } from '../parsers/ThemeRhemeParser';
import { AssetNode } from "../AssetNode";
import { WordNode } from '../parsers/NLParser';
import { AutoRuleNames } from './AutoRuleManager';


export class ThemeRhemeGazeRule extends AutoRule {

    /**
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(priority = 1, probability = 1) {
        super(AutoRuleNames.ThemeRhemeGaze, priority, probability);
    }

    _createNode() {
        let n = new AssetNode(AssetNodeType.ANIM);
        n.setAttribute('cat', 'glances');
        n.setAttribute('rule', AutoRuleNames.ThemeRhemeGaze);
        return n;
    }

    /**
     * Applies this rule and produces a list of lists of consecutive word nodes
     * which should have this rule applied to them
     * @param {Node} nlpTreeRoot
     * @param {Node[]} otherRoots
     * @return {Node[][]}
     * @private
     */
    _applyInternal(nlpTreeRoot: Node, otherRoots: Node[]): Node[][] {
        let sequences = [];
        if (!otherRoots || otherRoots.length === 0) {
            throw new Error(`Need ThemeRheme tree root`);
        }

        otherRoots[0].forEachChildType(NLPNodeType.SENTENCE, sentence => {
            sentence.forEachChildType(TRPart.TR as string, tr => {
                let theme = tr.findFirstChildType(TRPart.THEME as string);
                if (theme) {
                    let words = theme.gatherDescendantsType(NLPNodeType.WORD) as WordNode[];
                    // Remove expanded contraction words
                    for (let idx = 0; idx < words.length; idx++) {
                        if (words[idx].contractionBase) {
                            words.splice(idx, 1);
                        }
                    }
                    if (words.length > 1) {
                        sequences.push(words);
                    }
                }
            });
        });

        return sequences;
    }
}
