/*
 * Applies a list of para-linguistic behavior rules to an NLP or XML parse of a
 * sentence, producing a list output trees or nodes that will be inserted
 * automatically to produce a more character-rich experience.
 */

import JiboImport = require('../../../../../jibo');  // Just for typings, not available at runtime

import * as path from 'path';
import * as fs from 'fs';
import Node from 'jibo-node-xml';
import { WeightedRandomData } from 'jibo-cai-utils';
import { TagTreeNode } from '../TagTreeNode';
import { AutoRuleConfig } from '../../common/Types';
import { AutoRule } from './AutoRule';
// Punctuation
import { QuestionRule } from './QuestionRule';
import { CommaRule } from './CommaRule';
// Beat
import { InitiateRule } from './InitiateRule';
import { BlinkRule } from './BlinkRule';
import { DoubleBlinkRule } from './DoubleBlinkRule';
import { BeatBlinkRule } from './BeatBlinkRule';
// HotWords
import { HotWordsRule } from './HotWordsRule';
// Structure
import { OrRule } from './OrRule';
import { ButRule } from './ButRule';
import { NounRule } from './NounRule';
import { ListRule } from './ListRule';
//Timeline Modifying
import { TimelineAutoRule } from './timeline_mod/TimelineAutoRule';
import { TimelineAutoRuleData } from './timeline_mod/TimelineModUtils';
import { InterSentenceTimingRule } from './timeline_mod/InterSentenceTimingRule';
import { IntraSentenceTimingRule } from './timeline_mod/IntraSentenceTimingRule';
import { EllipsisRule } from './timeline_mod/EllipsisRule';
// Voice (Timeline Modifying)
import { EmotionalVoiceRule } from './timeline_mod/EmotionalVoiceRule';

import { speechLog } from '../../../log';
const log = speechLog.createChild("AutoRuleManager");

export const AutoRuleNames = {
  Exclamation: 'Exclamation',
  Question: 'Question',
  Blink: 'Blink',
  DoubleBlink: 'DoubleBlink',
  BeatBlink: 'BeatBlink',
  Comma: 'Comma',
  Or: 'Or',
  But: 'But',
  List: 'List',
  Noun: 'Noun',
  BeatFirstWordPart: 'BeatFirstWordPart',
  BeatNewWord: 'BeatNewWord',
  Initiate: "Initiate",
  Settle: "Settle",
  HotWords: 'HotWords',
  ThemeRhemeGaze: 'ThemeRhemeGaze'
};


export const TimelineModifyingRuleNames = {
  InterSentenceTiming: 'InterSentenceTiming',
  IntraSentenceTiming: 'IntraSentenceTiming',
  Ellipsis: 'Ellipsis',
  ExclamationVoice: 'ExclamationVoice',
  EmotionalVoice: 'EmotionalVoice'
};


export class AutoRuleManager {

  private hotWordMap = new Map<number, Map<string, WeightedRandomData[]>>();
  private rejectWordMap = new Map<string, string[]>();
  private descendingPhraseLengths: number[] = [];

  private rules: AutoRule[] = [
    new QuestionRule(2),
    new CommaRule(this._jibo, 5),
    new BlinkRule(3),
    new DoubleBlinkRule(3),
    new BeatBlinkRule(4),
    new ListRule(this._jibo, 10),
    new OrRule(this._jibo, 10),
    new ButRule(this._jibo, 10),
    new NounRule(10),
    new HotWordsRule(0, 1, this.hotWordMap, this.rejectWordMap, this.descendingPhraseLengths),
    new InitiateRule(this._jibo, 1),
  ];

  private timelineModRules: TimelineAutoRule[] = [
    new InterSentenceTimingRule(1),
    new IntraSentenceTimingRule(1),
    new EllipsisRule(1),
    new EmotionalVoiceRule(this._jibo, 1)
  ];

  constructor(private _jibo: typeof JiboImport) {

    // Generate the HotWords Mappings
    const hotWordsDir = this.retreiveHotWordsDir();
    if (hotWordsDir) {
      // TODO: Refactor to make asynchronous
      const hotWordCategoryFiles = fs.readdirSync(hotWordsDir);
      let hotWordCategories = [];

      log.debug(`Generating HotWords Match and Reject Maps`);
      hotWordCategoryFiles.forEach(hotWordCategoryFile => {
        const hotWordCategoryFilePath = path.join(hotWordsDir, hotWordCategoryFile);
        if (!fs.statSync(hotWordCategoryFilePath).isDirectory()) {
          // TODO: Refactor to make asynchronous
          try {
            hotWordCategories.push(JSON.parse(fs.readFileSync(hotWordCategoryFilePath, 'utf8')));
          } catch (err) {
            log.warn(`Unable to load/parse HotWord JSON '${hotWordCategoryFile}'; skipping...`, err);
          }
        }
      });

      hotWordCategories.forEach(hotWordMappings => {
        hotWordMappings.forEach(([hotWordMatchReject, weightedMatches]) => {
          hotWordMatchReject.forEach(matchRejectPair => {
            const match: string = matchRejectPair.match;
            const reject: string[] = matchRejectPair.reject;
            const length = match.trim().split(' ').length;
            let subMap = this.hotWordMap.get(length);
            if (!subMap) {
              subMap = new Map<string, WeightedRandomData[]>();
              this.hotWordMap.set(length, subMap);
              this.descendingPhraseLengths.push(length);
            }
            const keyName = match.toLowerCase();
            subMap.set(keyName, weightedMatches as WeightedRandomData[]);
            if (reject.length > 0) {
              this.rejectWordMap.set(keyName, reject.map(word => word.toLowerCase()));
            }
          });
        });
      });

      this.descendingPhraseLengths.sort((a, b) => { return b - a; });
    }
  }

  /**
   * Retrieves the HotWords mapping from `jibo-anim-db-animations`
   *
   * @return {string}
   */
  retreiveHotWordsDir(): string {
    // Attempt to find jibo-anim-db-animations project
    const resolvedPath = this._jibo.animDB.resolveAnimDB(this._jibo);
    let hotWordsDir: string;
    if (resolvedPath) {
      const rootPath = path.dirname(resolvedPath);
      hotWordsDir = path.join(rootPath, 'hot');
      if (!fs.existsSync(hotWordsDir)) {
        log.warn(`Module 'jibo-anim-db-animations' not found. HotWords will not work.`);
      }
    }
    return hotWordsDir;
  }

  /**
   * Applies a list of rules to an NLP tree generating a list of output trees.
   *
   * @param {Node} nlpTreeRoot
   * @param {AutoRuleConfig} autoRuleConfig
   * @return {Node[]}
   */
  applyRules(nlpTreeRoot, autoRuleConfig: AutoRuleConfig): Node[] {
    let out: Node[] = [];

    this.rules.forEach( rule => {
      switch (rule.ruleName) {
        case AutoRuleNames.Question:
        case AutoRuleNames.Comma:
          if (autoRuleConfig.punctuation) {
            out.push(rule.applyRule(nlpTreeRoot));
          }
          break;
        case AutoRuleNames.Or:
        case AutoRuleNames.But:
        case AutoRuleNames.List:
        case AutoRuleNames.Noun:
          if (autoRuleConfig.structure) {
            out.push(rule.applyRule(nlpTreeRoot));
          }
          break;
        case AutoRuleNames.Initiate:
        case AutoRuleNames.Blink:
        case AutoRuleNames.DoubleBlink:
        case AutoRuleNames.BeatBlink:
          if (autoRuleConfig.beat) {
            out.push(rule.applyRule(nlpTreeRoot));
          }
          break;
        case AutoRuleNames.HotWords:
          if (autoRuleConfig.hotWords) {
            out.push(rule.applyRule(nlpTreeRoot));
          }
          break;
        default:
          log.warn(`Unable to apply AutoRule: ${rule.ruleName}.`);
      }
    });

    return out;
  }

  /**
   * Applies a list of rules (if they were requested by the AutoRuleConfig) to an XML tree
   * generating a list of output trees.
   *
   * @param {TagTreeNode} xmlTree
   * @param {AutoRuleConfig} autoRuleConfig
   * @return {TimelineAutoRuleData[]}
   */
  applyTimelineModifyingRules(xmlTree: TagTreeNode, autoRuleConfig: AutoRuleConfig): TimelineAutoRuleData[] {

    let out = [] as TimelineAutoRuleData[];

    this.timelineModRules.forEach( rule => {
      switch (rule.ruleName) {
        case TimelineModifyingRuleNames.InterSentenceTiming:
          if (autoRuleConfig.interSentenceTiming) {
            out.push(rule.applyRule(xmlTree, autoRuleConfig.punctuation));
          }
          break;
        case TimelineModifyingRuleNames.IntraSentenceTiming:
          if (autoRuleConfig.intraSentenceTiming) {
            out.push(rule.applyRule(xmlTree));
          }
          break;
        case TimelineModifyingRuleNames.Ellipsis:
          if (autoRuleConfig.interSentenceTiming && autoRuleConfig.punctuation) {
            out.push(rule.applyRule(xmlTree));
          }
          break;
        case TimelineModifyingRuleNames.EmotionalVoice:
        case TimelineModifyingRuleNames.ExclamationVoice:
          if (autoRuleConfig.voice) {
            out.push(rule.applyRule(xmlTree));
          }
          break;
        default:
          log.warn(`Unable to apply AutoRule: ${rule.ruleName}.`);
      }
    });

    return out;
  }
}
