/*
 * @fileOverview
 * An auto rule which applies certain timing changes to intra-sentence modifiers
 * (e.g. or, but, ellipses).
 */

import Node from 'jibo-node-xml';
import { TimelineAutoRule } from './TimelineAutoRule';
import { TagTreeNode } from '../../TagTreeNode';
import { TimelineModifyingRuleNames } from '../AutoRuleManager';
import { AR_SUBRULE } from '../AutoRuleUtils';
import {
  TimelineModUtils,
  TimelineAutoRuleInsertionInfo,
  TimelineAutoRuleMatchInfo,
  TimelineAutoRuleType
} from './TimelineModUtils';

/**
 * Duration for a "but" pause inserted by AutoRules
 */
export const AR_BUT_PAU = 0.2;


/**
 * Duration for an "or" pause inserted by AutoRules
 */
export const AR_OR_PAU = 0.2;


export class IntraSentenceTimingRule extends TimelineAutoRule {

    /**
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(priority = 1, probability = 1) {
        super(TimelineModifyingRuleNames.IntraSentenceTiming, TimelineAutoRuleType.TIMEFUL, priority, probability);
    }

    /**
     * Create SSML/break node and gather insertion information
     *
     * @param {TimelineAutoRuleMatchInfo} matchInfo
     * @return {Array<Node, TimelineAutoRuleInsertionInfo>}
     * @private
     */
    _createTimelineModifyingData(matchInfo: TimelineAutoRuleMatchInfo): [Node, TimelineAutoRuleInsertionInfo] {

        let breakSize = 0;
        let offset = 1;
        switch (matchInfo.subRule) {
            case AR_SUBRULE.OR:
                breakSize = AR_OR_PAU;
                offset = 0;
                break;
            case AR_SUBRULE.BUT:
                breakSize = AR_BUT_PAU;
                offset = 0;
                break;
        }
        let n = TimelineModUtils.breakNodeBuilder(breakSize);
        return TimelineModUtils.getInsertionInfo(n, matchInfo.sibling, offset);
    }

    /**
     * Gathers all nodes that match any of the punctuation related to the IntraSentence timing rule (i.e. or, but, ...)
     *
     * @param {TagTreeNode} xmlTree
     * @return {Array<Array<Node, string>>}
     * @private
     */
    _applyInternal(xmlTree: TagTreeNode): TimelineAutoRuleMatchInfo[] {
        let matchesInfo: TimelineAutoRuleMatchInfo[] = [];

        xmlTree.forEachDescendant( node => {
            switch (node.value) {
                //case AR_SUBRULE.OR: // TODO: Add back once we have better support for autoRule configs on a per prompt basis
                case AR_SUBRULE.BUT:
                    matchesInfo.push({
                        sibling: node,
                        subRule: node.value
                    });
                    break;
            }
        });

        return matchesInfo;
    }

}
