import { StateMachine, State } from 'jibo-state-machine';
import { EmbodiedSpeech } from '../EmbodiedSpeech';

export class CompleteState extends State {

    constructor(sm: StateMachine, private es: EmbodiedSpeech, name: string) {
        super(sm, name);

        this.onEntry = async () => {
            this.es.jibo.performance.log('EmbodiedSpeechCenterRobotStopSkill', 'After end-speech clean-up is finished');
            this.es.log.info("Cleaning up session");
            await this.sm.stop();
        };
    }
}