/*
 * @fileOverview
 * An auto rule which wraps an exclamation (sentence) in an excited TTS voice configuration
 */

import Node from 'jibo-node-xml';
import { TimelineAutoRule } from './TimelineAutoRule';
import { TagTreeNode } from '../../TagTreeNode';
import { TimelineAutoRuleInsertionInfo, TimelineAutoRuleMatchInfo, TimelineAutoRuleType } from './TimelineModUtils';
import { TimelineModifyingRuleNames } from '../AutoRuleManager';
import { AR_SUBRULE } from '../AutoRuleUtils';
import { NodeType } from 'jibo-node-xml';


export class ExclamationVoiceRule extends TimelineAutoRule {

    /**
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(priority = 1, probability = 1) {
        super(TimelineModifyingRuleNames.ExclamationVoice, TimelineAutoRuleType.TIMELESS, priority, probability);
    }

    /**
     * Create TTSNode with ellipsis animation and gather insertion information
     *
     * @param {TimelineAutoRuleMatchInfo} matchInfo
     * @return {Array<Node, TimelineAutoRuleInsertionInfo>}
     * @private
     */
    _createTimelineModifyingData(matchInfo: TimelineAutoRuleMatchInfo): [Node, TimelineAutoRuleInsertionInfo] {
        let nodeToInsert = new Node('DEPRECATED');
        nodeToInsert.setAttribute('config', 'happy');
        const parent = matchInfo.children[0].parents[0];
        const insertionInfo: TimelineAutoRuleInsertionInfo = {
            nodes: [nodeToInsert],
            children: matchInfo.children
        };
        return [parent, insertionInfo];
    }

    /**
     * Gathers all nodes that contained with an exclamation sentence
     *
     * @param {TagTreeNode} xmlTree
     * @return {Array<Array<Node, string>>} Nodes that match and which rule was matched
     * @private
     */
    _applyInternal(xmlTree: TagTreeNode): TimelineAutoRuleMatchInfo[] {
        let matchesInfo: TimelineAutoRuleMatchInfo[] = [];
        let sentenceWords: Node[] = [];
        xmlTree.forEachDescendantType(NodeType.TEXT, node => {
            switch (node.value) {
                case AR_SUBRULE.PERIOD:
                case AR_SUBRULE.QUESTION:
                case AR_SUBRULE.COMMA:
                case AR_SUBRULE.ELLIPSIS:
                    sentenceWords = [];
                    break;
                case AR_SUBRULE.EXCLAMATION:
                    sentenceWords.push(node);
                    matchesInfo.push({
                        children: sentenceWords
                    });
                    sentenceWords = [];
                    break;
                default:
                    sentenceWords.push(node);
            }
        });

        return matchesInfo;
    }

}
