import Node from 'jibo-node-xml';
import { AttType } from 'jibo-node-xml';
import { AutoRule } from './AutoRule';
import { NLPNodeType, WordType, AssetNodeType } from '../../common/Types';
import { AssetNode } from "../AssetNode";
import { WordNode } from '../parsers/NLParser';
import { AutoRuleNames } from './AutoRuleManager';
import { NLPTools } from '../../utils/NLPTools';


/**
 * Nouns that are exempt from the noun rule
 */
export const AR_EXEMPT_NOUNS = new Set(['i', 'you', 'we', 'me']);


export class NounRule extends AutoRule {

    /**
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(priority = 1, probability = 1) {
        super(AutoRuleNames.Noun, priority, probability);
    }

    _createNode(children) {
      let atts = new Map<string, AttType>();
      atts.set('filter', '!down');
      let n = new AssetNode(AssetNodeType.ANIM, atts);
      n.setAttribute('nonBlocking', 'true');
      n.setAttribute('cat', 'glances');
      n.setAttribute('rule', AutoRuleNames.Noun);
      n.timeSyncNode = children[0];
      return n;
    }

    /**
     * Applies this rule and produces a list of lists of consecutive word nodes
     * which should have this rule applied to them
     *
     * @param {Node} nlpTreeRoot
     * @param {Node[]} [otherRoots]
     * @return {Node[][]}
     * @private
     */
    _applyInternal(nlpTreeRoot: Node, otherRoots?: Node[]): Node[][] {
      let sequences = [];
      let nounCount = 0;

      const wordAndPunctNodes = nlpTreeRoot.gatherDescendantsType(NLPNodeType.WORD) as WordNode[];
      const wordNodes = wordAndPunctNodes.filter(word => !NLPTools.isPunctuation(word.value));
      wordNodes.forEach( word => {
        if (!word.contractionBase && (word.wordType === WordType.NOUN) && !AR_EXEMPT_NOUNS.has(word.value.toLowerCase())) {
          sequences.push([word]);
          nounCount++;
        }
      });

      return sequences;
    }
}
