/*
 * @fileOverview
 * A superclass for all Timeline modifying autorules
 *
 * An autorule is a rule which takes as input an XML parsed tree
 * and produces TimelineAutoRuleData object which contains information about the rule,
 * where the rule matched in the given XML tree and all the nodes that could be inserted.
 *
 * Each auto rule bases its tag creation on some para-linguistic rule
 * about how we use non-verbal behavior to accompany speech.
 */

import Node from 'jibo-node-xml';
import { TagTreeNode } from '../../TagTreeNode';
import {
  TimelineAutoRuleInsertionInfo,
  TimelineAutoRuleData,
  TimelineAutoRuleMatchInfo,
  TimelineAutoRuleType
} from './TimelineModUtils';


export class TimelineAutoRule {

  /**
   * @param {String} ruleName the tag name for this behavior
   * @param {TimelineAutoRuleType} ruleType the type of this behavior
   * @param {Number} priority priority of rule with respect to other rules
   * @param {Number} probability probability of occurrence of rule
   */
  constructor(public ruleName: string, public ruleType: TimelineAutoRuleType, public priority: number, public probability = 1) { }

  /**
   * Applies this rule and produces a list of "tuples" containing information about what node
   * matches the rule and what rule was matched.
   *
   * @param {Node} xmlTree
   * @param {any} context
   * @return {Array<Array<Node,any>>}
   * @private
   */
  _applyInternal(xmlTree: TagTreeNode, context?: any): TimelineAutoRuleMatchInfo[]  {
    throw new Error('Should be implemented by subclass');
  }

  /**
   * Creates a "tuple" consisting of the parent node we will be inserting under as well as
   * the node and any placement information.
   *
   * @param {TimelineAutoRuleMatchInfo} matchInfo
   * @returns {Array<Node, TimelineAutoRuleInsertionInfo>}
   * @private
   */
  _createTimelineModifyingData(matchInfo: TimelineAutoRuleMatchInfo): [Node, TimelineAutoRuleInsertionInfo] {
    throw new Error('Should be implemented by subclass');
  }

  /**
   * Applies this rule and a TimelineAutoRuleData object which gives information on:
   * - What rule matches
   * - Some info about that rule (e.g. priority)
   * - Where the rule matched and the node to insert at those matches
   *
   * @param {TagTreeNode} xmlTree
   * @param {any} [context] Any contextual information a rule might need to properly apply the rule
   * @return {TimelineAutoRuleData}
   */
  applyRule(xmlTree: TagTreeNode, context?: any): TimelineAutoRuleData {

    // Get the list of sibling nodes to place rule node near
    let matches = this._applyInternal(xmlTree, context);

    let ruleData = {} as TimelineAutoRuleData;
    ruleData.autoRule = this.ruleName;
    ruleData.type = this.ruleType;
    ruleData.priority = this.priority;
    ruleData.matches = new Map<Node, TimelineAutoRuleInsertionInfo[]>();

    matches.forEach( matchInfo => {
      if (Math.random() < this.probability) {
        const [parent, nodeToInsertInfo] = this._createTimelineModifyingData(matchInfo);
        let childrenToInsert: TimelineAutoRuleInsertionInfo[] = ruleData.matches.get(parent);
        if (!childrenToInsert) {
          ruleData.matches.set(parent, childrenToInsert = [] as TimelineAutoRuleInsertionInfo[]);
        }
        childrenToInsert.push(nodeToInsertInfo);
      }
    });

    return ruleData;
  }
}
