// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../jibo');
// ------------------------------------------------

import { EmbodiedSpeech } from './speech/EmbodiedSpeech';
import { EmbodiedListen } from './listen/EmbodiedListen';
import { AutoRuleConfig, SpeakOptions } from './speech/common/Types';
import { CacheUtils } from 'jibo-cai-utils';

/**
 * Enum of Jibo's Embodied Dialog states
 * @typedef jibo.embodied#EmbodiedState
 * @property {string} IDLE
 * @property {string} SPEAKING
 * @property {string} LISTENING
 * @property {string} MIXED
 */
export enum EmbodiedState {
  IDLE = "IDLE",
  SPEAKING = "SPEAKING",
  LISTENING = "LISTENING",
  MIXED = "MIXED",
}

/**
 * Constructor options for the Jibo Embodied Dialog system
 * @memberof jibo.embodied
 * @interface EmbodiedOptions
 * @extends {jibo.embodied.speech.SpeakOptions}
 * @property {string} [resourceRoot] - Root directory of /animation and /audio resources
 */
export interface EmbodiedOptions extends SpeakOptions {
  resourceRoot?: string;
}

/**
 * @class jibo.embodied.EmbodiedDialog
 * @description Internal-only EmbodiedDialog class
 * @intdocs
 */
export class EmbodiedDialog {

  public speech: EmbodiedSpeech;
  public listen: EmbodiedListen;

  /**
   * Constructs Embodied Dialog instance
   */
  constructor() {
    this.speech = new EmbodiedSpeech(this);
    this.listen = new EmbodiedListen(this);
  }

  /**
   * Initializes Embodied Dialog instance.
   * @method jibo.embodied.EmbodiedDialog#init
   * @param {jibo} jibo jibo instance.
   * @param {jibo.embodied.EmbodiedOptions} [options] Options Embodied Speech will use to initialize with.
   * @param {jibo.embodied.speech.AutoRuleConfig} [esConfig] Configs Embodied Speech will use to initialize with
   * @returns {Promise<any>} Resolved when completed initialization
   * @intdocs
   */
  async init(jibo: typeof JiboImport, options?: EmbodiedOptions, esConfig?: AutoRuleConfig): Promise<any> {
    CacheUtils.initGlobalCache(jibo);
    const debug = options ? !!options.debugMode : false;
    await this.speech.init(jibo, debug, options, esConfig);
    await this.listen.init(jibo, debug);
  }

  /**
   * Get the state of Embodied Dialog
   * @method jibo.embodied.EmbodiedDialog#getState
   * @return {jibo.embodied#EmbodiedState} Embodied Dialog state (meta state based on state of ES and EL)
   * @intdocs
   */
  getState(): EmbodiedState  {
    const esActive = this.speech.isActive();
    const elState = this.listen.getCurrentState();

    if (!esActive && elState === this.listen._idle) {
      return EmbodiedState.IDLE;
    } else if (esActive && elState === this.listen._idle) {
      return EmbodiedState.SPEAKING;
    } else if (!esActive && elState !== this.listen._idle) {
      return EmbodiedState.LISTENING;
    } else {
      return EmbodiedState.MIXED;
    }
  }

}
