import Node from 'jibo-node-xml';
import { NLPNodeType, WordType } from '../../common/Types';
import { WordNode } from '../parsers/NLParser';
import { NLPTools } from '../../utils/NLPTools';


/**
 * Subrules that compose the larger AutoRules
 */
export const AR_SUBRULE = {
  PERIOD: '.',
  QUESTION: '?',
  EXCLAMATION: '!',
  COMMA: ',',
  ELLIPSIS: '...',
  OR: 'or',
  BUT: 'but',
  BLINK: 'single',
  DOUBLE_BLINK: 'double'
};


/**
 * Utility class that houses a number of useful functions for AutoRules
 */
export class AutoRuleUtils {

  /**
   * Extracts the last words in a sentence, choosing either all the words
   * in the last sentence part, or if it contains a verb then the verb and
   * all following words
   * @param {Node} sentenceNode
   * @return {List} list of consecutive word nodes
   */
  static getLastWordNodesInSentence(sentenceNode: Node): Node[] {
    let parts = sentenceNode.gatherChildrenType(NLPNodeType.PART);
    let lastPart = parts[parts.length - 1];

    let out: WordNode[] = [];

    // If there is no verb in the phrase, add it all
    if (!lastPart.getAttribute('verbCount')) {
      out = lastPart.gatherDescendantsType(NLPNodeType.WORD) as WordNode[];
    }
    // Otherwise only add words after and including verb
    else {
      let words = lastPart.gatherDescendantsType(NLPNodeType.WORD);

      words.forEach( (word: WordNode) => {
        // If this is the first verb, add it
        if (word.wordType === WordType.VERB) {
          out.push(word);
        }
        // If the verb has been found, add word
        else if (out.length > 0) {
          out.push(word);
        }
      });
    }

    return AutoRuleUtils.removeExpandedContractionWords(out);
  }

  /**
   * Extracts the sections of a sentence segmented by a given segment-er
   *
   * @param {string[]} segmenters
   * @param {Node} sentenceNode
   * @param {boolean} [keepPunct=false]
   * @return {Node[]}
   */
  static getWordsFromSentenceSegmentedBy(segmenters: string[], sentenceNode: Node, keepPunct: boolean = false) {

    let segments: WordNode[][] = [];

    let words = sentenceNode.gatherDescendantsType(NLPNodeType.WORD);
    words = AutoRuleUtils.removeExpandedContractionWords(words as WordNode[]);
    let segmenterCount = 0;
    segments[segmenterCount] = [];
    words.forEach( (word: WordNode) => {
      if (segmenters.indexOf(word.value) !== -1) {
        if (segments[segmenterCount].length > 0) {
          segmenterCount++;
          segments[segmenterCount] = [];
        }
      }
      if (keepPunct || !NLPTools.isPunctuation(word.value)) {
        segments[segmenterCount].push(word);
      }
    });

    return (segmenterCount > 0) ? segments : [];
  }

  /**
   * Remove all words from an array of WordNodes that are expansions of contractions
   *
   * @param {WordNode[]} words
   * @return {WordNode[]}
   */
  static removeExpandedContractionWords(words: WordNode[]): WordNode[] {
    for (let idx = 0; idx < words.length; idx++) {
      if (words[idx].contractionBase) {
        words.splice(idx, 1);
      }
    }
    return words;
  }

}