import Node from 'jibo-node-xml';
import { AttType } from 'jibo-node-xml';
import { SSMLNode } from '../../SSMLNode';
import { AssetNode } from '../../AssetNode';
import { SSMLNodeType, AssetNodeType } from '../../../common/Types';


/**
 * Wrapper interface that contains necessary information for TimelineAutoRule match
 */
export interface TimelineAutoRuleData {
  autoRule: string;
  type: TimelineAutoRuleType;
  priority: number;
  matches: Map<Node, TimelineAutoRuleInsertionInfo[]>;
}


/**
 * Types of Timeline-modifying auto rules
 */
export enum TimelineAutoRuleType {
  TIMELESS = "TIMELESS",
  TIMEFUL = "TIMEFUL",
}


/**
 * Types of Blink nodes
 */
export enum BlinkNodeType {
  SINGLE = "SINGLE",
  DOUBLE = "DOUBLE",
}


/**
 * Node, insertion offset information and optional children of said to-be-inserted node
 */
export interface TimelineAutoRuleInsertionInfo {
  nodes: Node[];
  offset?: number;
  children?: Node[];
}


/**
 *  Node, sub-rule and optional children associated with matching rule
 */
export interface TimelineAutoRuleMatchInfo {
  sibling?: Node;
  children?: Node[];
  subRule?: string;
}


/**
 * Utility class that houses a number of useful functions for Timeline Modifying AutoRules
 */
export class TimelineModUtils {

  /**
   * Create a break node of a given size (duration)
   *
   * @param {number} size
   * @return {Node} SSML/Break node
   */
  static breakNodeBuilder(size: number): Node {
    let nodeToInsert = new Node(SSMLNodeType.BREAK);
    nodeToInsert.setAttribute('size', (Math.round(size * 1e2) / 1e2));
    return nodeToInsert;
  }

  /**
   * Create a blink node of a given type (single, double)
   *
   * @param {BlinkNodeType} type
   * @return {AssetNode} Asset node
   */
  static blinkNodeBuilder(type: BlinkNodeType): AssetNode {
    let atts = new Map<string, AttType>();
    atts.set('filter', type);
    atts.set('layers', 'screen');
    atts.set('cat', 'blinks');
    let nodeToInsert = new AssetNode(AssetNodeType.ANIM, atts);
    return nodeToInsert;
  }

  /**
   * Create an SSML node of a given type and attribute combination
   *
   * @param {SSMLNodeType} type
   * @param {Object} attrs of type { [x: string]: AttType }
   * @return {SSMLNode} SSML node
   */
  static SSMLNodeBuilder(type: SSMLNodeType, attrs: { [x: string]: AttType }): SSMLNode {
    let nodeToInsert = new SSMLNode(type);
    Object.keys(attrs).forEach(key => {
      nodeToInsert.setAttribute(key, attrs[key]);
    });
    return nodeToInsert;
  }

  /**
   * Given a node to insert and a sibling to the node we want to insert, get the parent and placement (index) information
   *
   * @param {Node} nodeToInsert
   * @param {Node} siblingNode
   * @param {number} offset
   * @return {Array<Node, TimelineAutoRuleInsertionInfo>} Parent node to the node we will be inserting, the node to be inserted and placement info
   */
  static getInsertionInfo(nodeToInsert: Node, siblingNode: Node, offset: number): [Node, TimelineAutoRuleInsertionInfo] {
    const parent = siblingNode.parents[0];
    const insertIdx = parent.children.indexOf(siblingNode) + offset;
    const insertionInfo: TimelineAutoRuleInsertionInfo = {
      nodes: [nodeToInsert],
      offset: insertIdx
    };
    return [parent, insertionInfo];
  }

}