import { MetaLayerPresence, TTSFrame, AssetNodeType, TTSNodeType } from '../common/Types';
import { AssetNode } from '../processing/AssetNode';


export const TimelineLayerType = {
  ANIM: AssetNodeType.ANIM,
  TTS: TTSNodeType.TTS
};


export class TimelineFrame {

  constructor(public start: number, public stop: number, public data: any = undefined,
              public blocking: boolean = false, public prev: TimelineFrame = null,
              public next: TimelineFrame = null) {}

}


export class TimelineLayer {

  public _root: TimelineFrame = null;
  public length: number = 0;
  public start: number;
  public stop: number;

  constructor(public name: string, private _timeline: Timeline, private _frameBuffer: number, private _assetRelativeEnd: number, private _enableMerging: boolean = false) {  }

  /**
   * Insert a TimelineFrame into the current TimelineLayer (if nothing currently occupies
   * that time slot which is already utilizing the requested DOFs of the robot)
   *
   * @param {TimelineFrame} pendingFrame TimelineFrame to be inserted (if possible)
   * @param {boolean} [withBuffer=false] Toggle to respect the frameBuffer when inserting
   * @param {boolean} layerMergeOverride Value to override the initialized layerMerging value with
   * @return {boolean} Success or failure to insert thea supplied TimelineFrame
   */
  insert(pendingFrame: TimelineFrame, withBuffer: boolean = false, layerMergeOverride?: boolean): boolean {
    const pendingLayerData = (pendingFrame.data as AssetNode).playbackData.playbackLayers;
    if ((this._assetRelativeEnd !== undefined) && ((pendingFrame.stop > (this._timeline.tts.stop + this._assetRelativeEnd))) && !pendingLayerData.Audio) {
      return false;
    }
    const pendingFrameLayersAsInt = TimelineLayer._metaLayerToInt(pendingLayerData);
    const conflicts = this._gatherPotentialConflicts(pendingFrame, withBuffer);
    const allowMerging = (layerMergeOverride !== undefined) ? layerMergeOverride : this._enableMerging;
    let insert = (conflicts.length === 0);
    if (conflicts.length !== 0 && allowMerging) {
      insert = conflicts.every(frame => {
        let conflictLayerData = (frame.data as AssetNode).playbackData.playbackLayers;
        let layersAsInt = TimelineLayer._metaLayerToInt(conflictLayerData);
        let inConflict = layersAsInt & pendingFrameLayersAsInt;  // Logical AND
        return (inConflict === 0);  // No conflicts
      });
    }
    if (insert) {
      if ((this.start === undefined) || (pendingFrame.start < this.start)) {
        this.start = pendingFrame.start;
      }
      if ((this.stop === undefined) || (pendingFrame.stop > this.stop)) {
        this.stop = pendingFrame.stop;
      }
      this._insert(pendingFrame);
    }
    return insert;
  }

  /**
   * Given a MetaLayerPresence, yield an integer representation of those layers (derived from a bit array)
   *
   * @param {MetaLayerPresence} metaLayerPresence
   * @return {Number} Integer representation of the summation of the Layers as bits
   */
  static _metaLayerToInt(metaLayerPresence: MetaLayerPresence) {
    const layerBits = [
      Number(metaLayerPresence.Body),
      Number(metaLayerPresence.Screen),
      Number(metaLayerPresence.Audio)
    ];

    return parseInt(layerBits.join(''), 2);  // Convert boolean array (e.g. [1,0,0]) to integer (base 2)
  }

  /**
   * Gather all TimelineFrames that are present at the same time as the supplied TimelineFrame
   *
   * @param {TimelineFrame} pendingFrame TimelineFrame to be (possibly) inserted
   * @param {boolean} useBuffer Toggle to respect the frameBuffer when inserting
   * @return {TimelineFrame[]} Possibly conflicting frames
   */
  _gatherPotentialConflicts(pendingFrame: TimelineFrame, useBuffer: boolean): TimelineFrame[] {

    let currentFrame: TimelineFrame;
    let potentialConflicts: TimelineFrame[] = [];

    if (!this._root) {
      return potentialConflicts;
    } else {
      currentFrame = this._root;
      while (currentFrame) {
        const dynamicBuffer = (useBuffer ? this._frameBuffer : 0);
        const currentFrameStart = Math.round((currentFrame.start - dynamicBuffer) * 1000) / 1000;
        const currentFrameStop = Math.round((currentFrame.stop + dynamicBuffer) * 1000) / 1000;
        const pendingFrameStart = Math.round((pendingFrame.start - dynamicBuffer) * 1000) / 1000;
        const pendingFrameStop = Math.round((pendingFrame.stop + dynamicBuffer) * 1000) / 1000;

        // If the pending frame overlaps with the current frame
        if (pendingFrameStart < currentFrameStop && pendingFrameStop > currentFrameStart) {
          potentialConflicts.push(currentFrame);
        }
        currentFrame = currentFrame.next;
      }
    }

    return potentialConflicts;
  }

  /**
   * Insert TimelineFrame into the TimelineLayer
   *
   * @param {TimelineFrame} pendingFrame TimelineFrame to be inserted
   */
  _insert(pendingFrame: TimelineFrame): void {
    let currentFrame: TimelineFrame;
    let previousFrame: TimelineFrame;

    if (!this._root) {
      this._root = pendingFrame;
    } else {
      currentFrame = this._root;

      while (currentFrame) {
        if (pendingFrame.start <= currentFrame.start){
          pendingFrame.next = currentFrame;
          pendingFrame.prev = currentFrame.prev;
          if (currentFrame.prev) {
            currentFrame.prev.next = pendingFrame;
          }
          currentFrame.prev = pendingFrame;
          if (currentFrame === this._root) {
            this._root = pendingFrame;
          }
          this.length++;
          return;
        }
        previousFrame = currentFrame;
        currentFrame = currentFrame.next;
      }
      pendingFrame.prev = previousFrame;
      previousFrame.next = pendingFrame;
    }
    this.length++;
    return;
  }
}


export class Timeline {

  public tts: TimelineLayer;
  public anim: TimelineLayer;

  constructor (frameBuffer: number, assetRelativeEnd: number, enableLayerMerging: boolean = false) {
    this.tts = new TimelineLayer(TimelineLayerType.TTS, this, frameBuffer, assetRelativeEnd);
    this.anim = new TimelineLayer(TimelineLayerType.ANIM, this, frameBuffer, assetRelativeEnd, enableLayerMerging);
  }

  /**
   * Initialize a Timeline with TTS timing data
   *
   * @param {TTSFrame[]} ttsFrames Timing data for each TTS subsection
   */
  _init(ttsFrames: TTSFrame[]) {
    ttsFrames.forEach(frame => {
      if ((this.tts.start === undefined) || (frame.start < this.tts.start)) {
        this.tts.start = frame.start;
      }
      if ((this.tts.stop === undefined) || (frame.stop > this.tts.stop)) {
        this.tts.stop = frame.stop;
      }
      this.tts._insert(new TimelineFrame(frame.start, frame.stop, frame.data));
    });
  }

}
