import JiboImport = require('../../../../../jibo');  // Just for typings, not available at runtime

import * as _ from 'lodash/lodash.min';
import Node from 'jibo-node-xml';
import { AttType } from 'jibo-node-xml';
import { AutoRule } from './AutoRule';
import { NLPNodeType, AssetNodeType } from '../../common/Types';
import { AssetNode } from "../AssetNode";
import { SentenceNode, WordNode } from '../parsers/NLParser';
import { AutoRuleUtils } from './AutoRuleUtils';
import { AutoRuleNames } from './AutoRuleManager';


/**
 * Attribute keys utilized by the or rule to keep track of the positional/counts of or elements
 */
const AR_OR_SEGMENT_START_KEY = 'ar-or-segment-start';
const AR_OR_SEGMENT_STOP_KEY = 'ar-or-segment-stop';

/**
 * Keys file names utilized by the or rule
 */
export const OR_KEYS = [
    'Or_01',
    'Or_02',
    'Or_03'
];

/**
 * Number of words on either side of an "or" that we want to wrap in animation
 */
const NUM_WORDS_TO_WRAP = 5;


export class OrRule extends AutoRule {

    private Orientation = this.jibo.animDB.Orientation;
    private lastOrientation = (Math.random() > 0.5) ? this.Orientation.LEFT : this.Orientation.RIGHT;
    private currentSegmentAnim: string;

    /**
     * @param {jibo} jibo
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(private jibo: typeof JiboImport, priority = 1, probability = 1) {
        super(AutoRuleNames.Or, priority, probability);
    }

    _createNode(children: Node[]) {
        const newSegment = children[0].getAttribute(AR_OR_SEGMENT_START_KEY) as boolean;
        const endSegment = children[0].getAttribute(AR_OR_SEGMENT_STOP_KEY) as boolean;
        if (newSegment) {
            this.currentSegmentAnim = _.sample(OR_KEYS);
        }
        this.lastOrientation = this.lastOrientation === this.Orientation.LEFT ? this.Orientation.RIGHT : this.Orientation.LEFT;
        let atts = new Map<string, AttType>();
        let n = new AssetNode(AssetNodeType.ANIM, atts);
        n.setAttribute('name', this.currentSegmentAnim);
        n.setAttribute('orientation', this.lastOrientation);
        n.setAttribute('rule', AutoRuleNames.Or);
        n.setAttribute('endNeutral', 'false');
        if (endSegment) {
            n.setAttribute('endNeutral', 'true');
        }
        return n;
    }

    /**
     * Applies this rule and produces a list of lists of consecutive word nodes
     * which should have this rule applied to them
     * @param {Node} nlpTreeRoot
     * @param {Node[]} [otherRoots]
     * @return {Node[][]}
     * @private
     */
    _applyInternal(nlpTreeRoot: Node, otherRoots?: Node[]): Node[][] {
        let sequences = [];

        nlpTreeRoot.forEachChildType(NLPNodeType.SENTENCE, (sentence: SentenceNode) => {
            let wordSegments = AutoRuleUtils.getWordsFromSentenceSegmentedBy(['or'], sentence, true);
            if (wordSegments.length > 0) {
                const zippedWordSegments = wordSegments.map(arr => [arr, arr.map(wordNode => wordNode.value)]);
                let segmentIdx = 0;
                let endSegment: Node[];
                zippedWordSegments.forEach( nodesAndStrings => {
                    const [nodes, strings] = nodesAndStrings as [WordNode[], string[]];
                    let choppedWordSegment: Node[];
                    if (segmentIdx === 0) {  // If it's BEFORE the first OR, take the words next to the it (but after a comma)
                        let commaIndex = strings.lastIndexOf(',');
                        if (commaIndex !== -1) {
                            nodes.splice(0, nodes.length - commaIndex - 1);
                        }
                        choppedWordSegment = nodes.slice(-NUM_WORDS_TO_WRAP);
                    } else { // If it's AFTER the first OR, take the words next to the it (but only up to a comma)
                        let commaIndex = strings.indexOf(',');
                        if (commaIndex !== -1) {
                            nodes.splice(commaIndex, nodes.length - commaIndex);
                        }
                        choppedWordSegment = nodes.slice(0, NUM_WORDS_TO_WRAP);
                    }
                    if (choppedWordSegment.length > 0) {
                        if (segmentIdx === 0) {
                            choppedWordSegment[0].setAttribute(AR_OR_SEGMENT_START_KEY, true);
                        } else {
                            endSegment = choppedWordSegment;
                        }
                        sequences.push(choppedWordSegment);
                    }
                    segmentIdx++;
                });
                if (endSegment) {
                    endSegment[0].setAttribute(AR_OR_SEGMENT_STOP_KEY, true);
                }
            }
        });

        return sequences;
    }



}
