/*
 * @fileOverview
 * A superclass for all autorules
 * An autorule is a rule which takes as input at least a NLP parse tree from
 * the NLParser and produces an input tree with behavior tags.
 * Each auto rule bases its tag creation on some para-linguistic rule
 * about how we use non-verbal behavior to accompany speech.
 *
 * @author Siggi <siggi@jibo.com>
 * Created on 11/7/15.
 */

import Node from 'jibo-node-xml';
import { NodeType } from 'jibo-node-xml';


export class AutoRule {

  /**
   * @param {String} ruleName the tag name for this behavior
   * @param {Number} priority priority of rule with respect to other rules
   * @param {Number} probability probability of occurrence of rule
   */
  constructor(public ruleName: string, public priority: number, public probability = 1) {
    // noop
  }

  /**
   * Applies this rule and produces a list of lists of consecutive word nodes
   * which should have this rule applied to them
   * @param {Node} nlpTreeRoot
   * @param {Node[]} [otherRoots]
   * @return {Node[][]}
   * @private
   */
  _applyInternal(nlpTreeRoot: Node, otherRoots?: Node[]): Node[][] {
    throw new Error('Should be implemented by subclass');
  }

  /**
   * Creates a node of type that is appropriate for this rule. The node should have
   * no children as those will be added later
   * @returns {Node}
   * @private
   */
  _createNode(children?: Node[], subRule?: string): Node {
    throw new Error('Should be implemented by subclass');
  }

  /**
   * Applies this rule and produces an output tree
   * @param {Node} nlpTreeRoot
   * @param {Node[]} [otherRoots]
   * @return {Node}
   */
  applyRule(nlpTreeRoot: Node, otherRoots?: Node[]): Node {

    // Get the list of word sequences
    let wordSequences = this._applyInternal(nlpTreeRoot, otherRoots);

    let root = new Node(NodeType.ROOT);
    root.setAttribute('autoRule', this.ruleName);
    root.setAttribute('priority', this.priority);

    wordSequences.forEach(sequence => {
      // With random chance we create a tag for this rule
      if (Math.random() < this.probability) {
        const newNode = this._createNode(sequence);
        if (newNode) {
          // Add all words in sequence to this tag
          sequence.forEach(wordNode => newNode.addChild(wordNode));

          root.addChild(newNode);
        }
      }
    });

    return root;
  }
}
