import JiboImport = require('../../../../jibo');

type KeyFrameType = JiboImport.animDB.KeyFrameType;
type Anim = JiboImport.animDB.Anim;
type AudioEventKF = JiboImport.animDB.format_0_6_x.AudioEventKF;
type Layer<T extends KeyFrameType>  = JiboImport.animDB.format_0_6_x.Layer<T>;
type KeyFrame<T extends KeyFrameType> = JiboImport.animDB.KeyFrame<T>;

/**
 * @private
 */
export class AudioAnimTemplate implements Anim {

  public version = '0.7.0';
  public framerate = 30;
  public scale = 1;
  public layers: Layer<AudioEventKF>[];
  public animdb = {
    name: 'audio_path_tag',
    metaTerms: [ "audio-only" ],
    scaleMax: 1,
    scaleMin: 1,
    speedMax: 1,
    speedMin: 1
  };
  public pathless = true;

  constructor(public duration: number, path: string) {

    let audioEvent = {} as AudioEventKF;
    audioEvent.AudioEvent = {
      file: path
    };

    let keyframe = {} as KeyFrame<AudioEventKF>;
    keyframe.time = 0;
    keyframe.value = audioEvent;

    let layer = {} as Layer<AudioEventKF>;
    layer.id = '96ca2c12e2f4459589c8dd99387ab59e';
    layer.name = 'Audio Event';
    layer.type = 'Audio Event';
    layer.visible = true;
    layer.locked = false;
    layer.keyframes = [keyframe];

    this.layers = [layer];
  }
}

export {}; // Workaround to provide non-empty typings export
