// Lists origin:  https://github.com/web-mech/badwords-list (MIT License)
const ContentLists = require('../../../resources/swears.json');

export class ContentValidator {

    private blacklist: RegExp;
    private whitelist: RegExp;

    constructor() {
        // REGEX that detects word boundary swears (e.g. fuck or fuckfuckfuck)
        const reWholeMatch = `\\b(${ContentLists.whole.join('|')})+\\b`;
        // REGEX that detects swears embedded in other words (e.g. fuckface) but allows some (e.g. assume, arsenal)
        const rePartialMatch = `(\\w*(${ContentLists.partial.join('|')})\\w*)`;
        // REGEX that is the union of the two above checks.
        const reBlackList = `${reWholeMatch}|${rePartialMatch}`;
        // REGEX that detects white listed words/phrases (e.g. Alan Cumming)
        const reWhitelist = `(\\b(${ContentLists.whitelist.join('|')})\\b)`;
        this.blacklist = new RegExp(reBlackList, 'ig');
        this.whitelist = new RegExp(reWhitelist, 'ig');
    }

    /**
     * Check a given input string of text for containing restricted words
     * @param {string} sentence - String to have restricted words replaced
     * @param {string} replacement - Replacement string to swap in
     * @returns {string} String with all replacements swapped in
     */
    replaceRestricted(sentence: string, replacement: string): string {
        this.blacklist.lastIndex = 0;
        this.whitelist.lastIndex = 0;

        let saved = {};
        let count = 0;
        let ids = [];
        const hider = (match) => {
            const id = `<wl id=${count++}\/>`;
            ids.push(id);
            saved[id] = match;
            return id;
        };
        const seeker = (match) => {
            return saved[match];
        };

        const hidden = sentence.replace(this.whitelist, hider);
        const replaced = hidden.replace(this.blacklist, replacement);
        if (ids.length) {
            const reSavelist = `(${ids.join('|')})`;
            const savelist = new RegExp(reSavelist, 'g');
            return replaced.replace(savelist, seeker);
        }
        return replaced;
    }

}