/*
 * @fileOverview
 * An auto rule which applies a blocking ellipsis animation alongside ellipses in the timeline.
 */

import Node from 'jibo-node-xml';
import { TimelineAutoRule } from './TimelineAutoRule';
import { TagTreeNode } from '../../TagTreeNode';
import { AssetNode } from '../../AssetNode';
import { AssetNodeType } from '../../../common/Types';
import { InputProcessor } from '../../InputProcessor';
import { TimelineModifyingRuleNames } from '../AutoRuleManager';
import { AR_SUBRULE } from '../AutoRuleUtils';
import {
  TimelineModUtils,
  TimelineAutoRuleInsertionInfo,
  TimelineAutoRuleMatchInfo,
  TimelineAutoRuleType
} from './TimelineModUtils';

export class EllipsisRule extends TimelineAutoRule {

    /**
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(priority = 1, probability = 1) {
        super(TimelineModifyingRuleNames.Ellipsis, TimelineAutoRuleType.TIMEFUL, priority, probability);
    }

    /**
     * Create AssetNode with ellipsis animation and gather insertion information
     *
     * @param {TimelineAutoRuleMatchInfo} matchInfo
     * @return {Array<Node, TimelineAutoRuleInsertionInfo>}
     * @private
     */
    _createTimelineModifyingData(matchInfo: TimelineAutoRuleMatchInfo): [Node, TimelineAutoRuleInsertionInfo] {
        const offset = 1;
        let n = new AssetNode(AssetNodeType.ANIM);
        n.setAttribute('cat', 'ellipsis');

        return TimelineModUtils.getInsertionInfo(n, matchInfo.sibling, offset);
    }

    /**
     * Gathers all nodes that contain ellipsis
     *
     * @param {TagTreeNode} xmlTree
     * @return {Array<Array<Node, string>>} Nodes that match and which rule was matched
     * @private
     */
    _applyInternal(xmlTree: TagTreeNode): TimelineAutoRuleMatchInfo[] {
        let matchesInfo: TimelineAutoRuleMatchInfo[] = [];

        xmlTree.forEachDescendant( node => {
            if (node.value === AR_SUBRULE.ELLIPSIS) {
                let ancestorConflict = false;
                node.forEachAncestor( ancestor => {
                    if (InputProcessor.isAsset(ancestor)) {
                        ancestorConflict = true;
                    }
                });
                if (!ancestorConflict) {
                    matchesInfo.push({
                        sibling: node,
                        subRule: AR_SUBRULE.ELLIPSIS
                    });
                }
            }
        });

        return matchesInfo;
    }

}
