import Node from 'jibo-node-xml';
import { AutoRule } from './AutoRule';
import { NLPNodeType, SentenceType } from '../../common/Types';
import { WordNode } from '../parsers/NLParser';
import { AutoRuleNames } from './AutoRuleManager';
import { TimelineModUtils, BlinkNodeType } from './timeline_mod/TimelineModUtils';
import { AssetNode } from '../AssetNode';
import { AutoRuleUtils } from './AutoRuleUtils';


export class BlinkRule extends AutoRule {

    /**
     * @param {Number} priority priority of rule with respect to other rules
     * @param {Number} probability probability of occurrence of rule
     */
    constructor(priority = 1, probability = 1) {
        super(AutoRuleNames.Blink, priority, probability);
    }

    _createNode(children?: Node[]) {
        let n: AssetNode = TimelineModUtils.blinkNodeBuilder(BlinkNodeType.SINGLE);
        n.setAttribute('nonBlocking', 'true');
        n.setAttribute('position', 'after');
        n.setAttribute('rule', AutoRuleNames.Blink);
        n.timeSyncNode = children[0];
        return n;
    }

    /**
     * Applies this rule and produces a list of lists of consecutive word nodes
     * which should have this rule applied to them
     * @param {Node} nlpTreeRoot
     * @param {Node[]} [otherRoots]
     * @return {Node[][]}
     * @private
     */
    _applyInternal(nlpTreeRoot: Node, otherRoots?: Node[]): Node[][] {
        let sequences = [];

        nlpTreeRoot.forEachChildType(NLPNodeType.SENTENCE, sentence => {
            const sentenceType = sentence.getAttribute('sentenceType');
            if (sentenceType === SentenceType.REGULAR || sentenceType === SentenceType.EXCLAMATION) {
                let words = sentence.gatherDescendantsType(NLPNodeType.WORD);
                words = AutoRuleUtils.removeExpandedContractionWords(words as WordNode[]);
                if (words) {
                    sequences.push(words.slice(-1));
                }
            }
        });

        return sequences;
    }
}
