import Node from 'jibo-node-xml';
import { StateMachine, State, Transition } from 'jibo-state-machine';
import { TagTreeNode } from '../processing/TagTreeNode';
import { EmbodiedSpeech } from '../EmbodiedSpeech';
import { InputProcessor } from '../processing/InputProcessor';
import { Dataflow } from '../common/Types';


export class CreateTimelineState extends State {

    constructor(sm: StateMachine, private es: EmbodiedSpeech, name: string) {
        super(sm, name);

        this.onEntry = async (transition: Transition, data: Dataflow) => {
            let preInputTree: TagTreeNode;
            let nlParseTree: Node;
            let autoTagTrees: Node[];
            this.es.jibo.performance.log('EmbodiedSpeechBuildingStartSkill', 'When ES starts building structures for dispatch');
            // Process text into constituent trees (Input and Auto-tag)
            this.es.log.debug("Generating pre-Input Tree");
            preInputTree = await this.es.inputProcessor.generatePreInputTree(data.textToSpeak);
            if (!data.speakOptions.disableAutoRules) {
                this.es.log.debug("Applying Timeline-modifying Auto Rules");
                const timelineAutoRuleMatches = this.es.autoRuleManager.applyTimelineModifyingRules(preInputTree, data.autoRuleConfig);
                preInputTree = this.es.inputProcessor.insertTimelineAutoRules(preInputTree, timelineAutoRuleMatches);
            }
            this.es.log.debug("Cleaning input and generating NL Parse Tree");
            const cleanTextArray = InputProcessor.getPlainTextArrayFromTree(preInputTree);
            nlParseTree = await this.es.nlParser.parse(cleanTextArray, preInputTree.expansions, preInputTree.contractions);
            if (!data.speakOptions.disableAutoRules) {
                this.es.log.debug("Applying standard Auto Rules");
                autoTagTrees = this.es.autoRuleManager.applyRules(nlParseTree, data.autoRuleConfig);
            }
            this.es.log.debug("Generating Input Tree");
            const inputTree = InputProcessor.generateInputTree(preInputTree, nlParseTree);
            this.es.jibo.performance.log('EmbodiedSpeechBuildingTreesCompleteSkill', 'When ES completes building trees for timelines');
            // Generate Timeline from Input and Auto-tag trees
            this.es.log.debug("Generating Timeline of TTS and Animations");
            const timeline = await this.es.timelineManager.generateTimeline(inputTree, data.speakOptions, autoTagTrees);
            this.es.jibo.performance.log('EmbodiedSpeechBuildingTimelinesCompleteSkill', 'When ES completes building timelines for dispatch');
            data.timeline = timeline;
            return data;
        };
    }

}