import Node from 'jibo-node-xml';
import { NodeType } from 'jibo-node-xml';
import { NLPNodeType } from '../../common/Types';

/**
 * This method inspects the input node and if it is of type NLPNodeType.WORD
 * it adds it as child to out, otherwise it adds all descendants of node that
 * have type NLPNodeType.WORD as children to out
 * @param {Node} node Input node
 * @param {Node} out Output node
 */
function addAllWords(node: Node, out: Node) {
  if (node.type === NLPNodeType.WORD) {
    out.addChild(node);
  }
  else {
    node.forEachDescendantType(NLPNodeType.WORD, n => {
      out.addChild(n);
    });
  }
}

/**
 * Takes a verb part node and breaks its word children into
 * pre-verbal, verbal, and post-verbal parts
 * @param {Node} vp
 * @param {Node} preV
 * @param {Node} V
 * @param {Node} postV
 */
function parseVP(vp: Node, preV: Node, V: Node, postV: Node) {
  // If this VP contains another VP
  let internalVP = vp.findFirstChildType('VP');

  // If we are the deepest VP
  if (!internalVP) {
    let verbDone = false;
    for (let i = 0; i < vp.children.length; i++) {
      let node = vp.children[i];
      if (!verbDone) {
        if (node.type !== NLPNodeType.WORD) {
          verbDone = true;
          addAllWords(node, postV);
        }
        else {
          addAllWords(node, V);
        }
      }
      else {
        addAllWords(node, postV);
      }
    }
  }
  else {
    for (let i = 0; i < vp.children.length; i++) {
      let node = vp.children[i];
      if (node.type === 'VP') {
        if (i !== vp.children.length-1) {
          throw Error(`Don't think that this should happen`);
        }
        parseVP(node, preV, V, postV);
      }
      else {
        addAllWords(node, preV);
      }
    }
  }
}



/** @enum {String} */
export const VerbPart = {
  COMPLEX: 'COMPLEX',
  PRE: 'PRE',
  V: 'V',
  POST: 'POST',
};



/** @enum {String} */
export const TRPart = {
  TR: 'TR',
  THEME: 'THEME',
  RHEME: 'RHEME',
};



export class ThemeRhemeParser {

  parse(nlpTreeRoot: Node) {
    let tempRoot = new Node(NodeType.ROOT);

    for (let j = 0; j < nlpTreeRoot.children.length; j++) {
      let node = nlpTreeRoot.children[j];

      if (node.type === NLPNodeType.WORD) {
        tempRoot.addChild(node);
      }
      else if (node.type === NLPNodeType.SENTENCE) {
        let newSentence = node.cloneShallow();
        tempRoot.addChild(newSentence);

        for (let k = 0; k < node.children.length; k++) {
          let node2 = node.children[k];
          if (node2.type === NLPNodeType.PART) {
            let complex = new Node(VerbPart.COMPLEX);
            newSentence.addChild(complex);
            let preV = new Node(VerbPart.PRE);
            let V = new Node(VerbPart.V);
            let postV = new Node(VerbPart.POST);
            complex.addChild(preV);
            complex.addChild(V);
            complex.addChild(postV);

            // Populate preverb
            for (let i = 0; i < node2.children.length; i++) {
              let n = node2.children[i];
              if (n.type === 'VP') {
                parseVP(n, preV, V, postV);
                break;
              }
              else {
                addAllWords(n, preV);
              }
            }
            if (!V.children.length) {
              complex.att.set('noVerb', true);
            }
          }
          else if (node2.type === NLPNodeType.WORD) {
            newSentence.addChild(node2);
          }
          else {
            throw Error(`Shouldn't happen`);
          }
        }

        // Now we find which parts have new words in them
        newSentence.forEachChildType(VerbPart.COMPLEX as string, compl => {
          compl.att.set('newCount', 0);
          compl.forEachChild(part => {
            part.att.set('newCount', 0);
            part.forEachChildType(NLPNodeType.WORD, c => {
              if (c.att.get('new')) {
                part.modifyAttribute('newCount', (old: number) => old + 1);
              }
            });
            compl.modifyAttribute('newCount', (old: number) => {
              return old + (part.getAttribute('newCount') as number);
            });
          });
        });
      }
      else {
        throw Error(`Shouldn't happen`);
      }
    }

    // Finally we new create our Theme Rheme tree
    let newRoot = new Node(NodeType.ROOT);
    for (let i = 0; i < tempRoot.children.length; i++) {
      let c = tempRoot.children[i];
      if (c.type === NLPNodeType.SENTENCE) {
        let newSentence = c.cloneShallow();
        newRoot.addChild(newSentence);
        c.forEachChild(n => {
          if (n.type === VerbPart.COMPLEX) {
            let tr = new Node(TRPart.TR);
            let theme = new Node(TRPart.THEME);
            let rheme = new Node(TRPart.RHEME);
            newSentence.addChild(tr);

            let pre = n.children[0];
            let v = n.children[1];
            let post = n.children[2];

            let flipped = false;
            if (!this._hasNewCount(pre)) {
              // !pre && !post
              if (!this._hasNewCount(post)) {
                theme.addChild(pre);
                rheme.addChild(v);
                rheme.addChild(post);
              }
              // !pre && post
              else {
                theme.addChild(pre);
                theme.addChild(v);
                rheme.addChild(post);
              }
            }
            else {
              if (!this._hasNewCount(post)) {
                // pre && !post && !v
                if (!this._hasNewCount(v)) {
                  rheme.addChild(pre);
                  theme.addChild(v);
                  theme.addChild(post);

                  tr.addChild(rheme);
                  tr.addChild(theme);
                  flipped = true;
                }
                // pre && !post && v
                else {
                  theme.addChild(pre);
                  rheme.addChild(v);
                  rheme.addChild(post);
                }
              }
              // pre && post
              else {
                theme.addChild(pre);
                theme.addChild(v);
                rheme.addChild(post);
              }
            }
            if (!flipped) {
              tr.addChild(theme);
              tr.addChild(rheme);
            }
          }
          else if (n.type === NLPNodeType.WORD) {
            newSentence.addChild(n);
          }
          else {
            throw Error(`Shouldn't happen`);
          }
        });
      }
      else if (c.type === NLPNodeType.WORD) {
        newRoot.addChild(c);
      }
      else {
        throw Error(`Shouldn't happen`);
      }
    }

    return newRoot;
  }

  _hasNewCount(node: Node) {
    let n = node.att.get('newCount');
    return !!n;
  }
}
